export default [
  // ─── Domain 1: General Security Concepts (~36 cards) ───────────────────────

  { id: 'fc001', domainId: 1, front: 'CIA Triad', back: 'The three core principles of information security: Confidentiality (preventing unauthorized disclosure), Integrity (ensuring data is accurate and unaltered), and Availability (ensuring systems and data are accessible when needed). Every security control maps back to protecting one or more of these properties.' },
  { id: 'fc002', domainId: 1, front: 'AAA Framework', back: 'Authentication (verifying identity), Authorization (granting appropriate access), and Accounting (logging actions for audit). AAA is the foundation of access control in networks and systems. RADIUS and TACACS+ are common AAA protocols.' },
  { id: 'fc003', domainId: 1, front: 'Multi-Factor Authentication (MFA)', back: 'Requires two or more distinct authentication factors: something you know (password/PIN), something you have (token/smart card), something you are (biometrics), somewhere you are (geolocation), or something you do (behavioral). Combining factors from different categories dramatically reduces the risk of credential compromise.' },
  { id: 'fc004', domainId: 1, front: 'Something You Know (authentication factor)', back: 'A knowledge-based authentication factor such as passwords, PINs, or security question answers. It is the weakest single factor because it can be stolen, guessed, or phished. Always combine with at least one additional factor for sensitive systems.' },
  { id: 'fc005', domainId: 1, front: 'Something You Have (authentication factor)', back: 'A possession-based factor such as hardware tokens (RSA SecurID), smart cards, FIDO2 keys, or OTP apps (Google Authenticator). Physical possession is required, making remote attacks more difficult. Loss of the token is a significant risk.' },
  { id: 'fc006', domainId: 1, front: 'Something You Are (authentication factor)', back: 'A biometric factor including fingerprint scans, iris recognition, facial recognition, and voice patterns. Biometrics cannot be forgotten or easily shared, but enrollment errors create false acceptance rates (FAR) and false rejection rates (FRR). The crossover error rate (CER/EER) measures accuracy.' },
  { id: 'fc007', domainId: 1, front: 'Symmetric Encryption', back: 'Uses a single shared secret key for both encryption and decryption. It is fast and efficient for large data volumes (bulk encryption). Key distribution is the major challenge — both parties must securely exchange the key beforehand. Examples: AES, 3DES, ChaCha20.' },
  { id: 'fc008', domainId: 1, front: 'Asymmetric Encryption', back: 'Uses a mathematically linked key pair: a public key (freely shared) for encryption or signature verification, and a private key (kept secret) for decryption or signing. Solves the key-distribution problem but is computationally slower than symmetric encryption. Examples: RSA, ECC, Diffie-Hellman.' },
  { id: 'fc009', domainId: 1, front: 'AES (Advanced Encryption Standard)', back: 'The current standard symmetric block cipher, operating on 128-bit blocks with key sizes of 128, 192, or 256 bits. AES-256 is considered quantum-resistant for the near term. It replaced DES and 3DES and is used in TLS, disk encryption (BitLocker, FileVault), and wireless (WPA3).' },
  { id: 'fc010', domainId: 1, front: 'RSA (Rivest–Shamir–Adleman)', back: 'A widely used asymmetric algorithm whose security relies on the difficulty of factoring large prime numbers. Common key sizes are 2048 and 4096 bits — 1024-bit RSA is no longer considered secure. RSA is used for key exchange, digital signatures, and certificate-based authentication.' },
  { id: 'fc011', domainId: 1, front: 'Elliptic Curve Cryptography (ECC)', back: 'An asymmetric algorithm that provides equivalent security to RSA with much smaller key sizes (e.g., 256-bit ECC ≈ 3072-bit RSA). Smaller keys mean faster computation and lower power usage, making ECC ideal for mobile and IoT devices. Used in ECDHE key exchange and ECDSA signatures.' },
  { id: 'fc012', domainId: 1, front: 'Hashing', back: 'A one-way function that converts input data of any size into a fixed-length digest (hash value). Hashes are used to verify data integrity — any change to the input produces a different hash. Common algorithms: SHA-256, SHA-3. MD5 and SHA-1 are cryptographically broken and deprecated.' },
  { id: 'fc013', domainId: 1, front: 'Digital Signature', back: 'Created by hashing data and then encrypting the hash with the sender\'s private key. Recipients verify the signature by decrypting with the sender\'s public key and comparing hashes. Digital signatures provide authentication, integrity, and non-repudiation simultaneously.' },
  { id: 'fc014', domainId: 1, front: 'PKI (Public Key Infrastructure)', back: 'A framework of policies, procedures, hardware, software, and people that manages the lifecycle of digital certificates. Key components include the Certificate Authority (CA), Registration Authority (RA), certificate revocation lists (CRL), and OCSP. PKI enables trusted encrypted communications and digital signatures at scale.' },
  { id: 'fc015', domainId: 1, front: 'Certificate Authority (CA)', back: 'A trusted entity that issues, signs, renews, and revokes digital certificates. A Root CA sits at the top of the trust hierarchy and signs Intermediate CAs, which in turn sign end-entity certificates. The root CA\'s private key is kept offline for maximum security.' },
  { id: 'fc016', domainId: 1, front: 'Certificate Revocation List (CRL) vs. OCSP', back: 'A CRL is a periodically published list of revoked certificate serial numbers. OCSP (Online Certificate Status Protocol) provides real-time, per-certificate revocation checking. OCSP Stapling improves performance by letting the server cache and present its own OCSP response to clients.' },
  { id: 'fc017', domainId: 1, front: 'X.509 Certificate', back: 'The standard format for digital certificates. An X.509 certificate contains the subject\'s public key, identity information, issuer (CA) details, validity period, serial number, and the CA\'s digital signature. Extensions like SAN (Subject Alternative Name) allow a single certificate to cover multiple domains.' },
  { id: 'fc018', domainId: 1, front: 'Zero Trust Architecture', back: 'A security model based on the principle "never trust, always verify." No user, device, or network segment is inherently trusted — every access request must be authenticated, authorized, and continuously validated regardless of location. Microsegmentation and least privilege are core implementation techniques.' },
  { id: 'fc019', domainId: 1, front: 'Least Privilege Principle', back: 'Users, processes, and systems should be granted only the minimum permissions necessary to perform their functions. Excess privilege increases the blast radius of compromised accounts or processes. Regular access reviews and privilege creep audits are essential to maintaining least privilege.' },
  { id: 'fc020', domainId: 1, front: 'Defense in Depth', back: 'A layered security strategy that uses multiple overlapping controls so that the failure of one control does not expose the entire system. Layers typically include physical security, network controls, endpoint protection, application security, data controls, and security monitoring.' },
  { id: 'fc021', domainId: 1, front: 'Preventive Security Control', back: 'A control designed to stop a security incident from occurring. Examples include firewalls, access controls, encryption, and MFA. Preventive controls are the first line of defense and are most effective when combined with detective and corrective controls.' },
  { id: 'fc022', domainId: 1, front: 'Detective Security Control', back: 'A control designed to identify and alert on security events after or as they occur. Examples include IDS, SIEM, audit logs, and security cameras. Detective controls are essential because no set of preventive controls is perfect.' },
  { id: 'fc023', domainId: 1, front: 'Corrective Security Control', back: 'A control that restores systems to normal after a security incident. Examples include patch management, system backups and restores, and incident response playbooks. Corrective controls minimize the impact and duration of security incidents.' },
  { id: 'fc024', domainId: 1, front: 'Compensating Security Control', back: 'An alternative control implemented when a primary control is not feasible or too costly. For example, network segmentation may compensate for an inability to patch a legacy system. Compensating controls must provide equivalent protection to the original requirement, particularly in compliance frameworks like PCI-DSS.' },
  { id: 'fc025', domainId: 1, front: 'NIST Cybersecurity Framework (CSF)', back: 'A voluntary framework from the National Institute of Standards and Technology organized around five core functions: Identify, Protect, Detect, Respond, and Recover. CSF 2.0 added a sixth function: Govern. It provides a common language for organizations to manage and communicate cybersecurity risk.' },
  { id: 'fc026', domainId: 1, front: 'ISO/IEC 27001', back: 'An international standard for establishing, implementing, maintaining, and continually improving an Information Security Management System (ISMS). Organizations can pursue formal certification after a third-party audit. Annex A contains 93 controls across four themes: organizational, people, physical, and technological.' },
  { id: 'fc027', domainId: 1, front: 'CIS Controls', back: 'The Center for Internet Security\'s prioritized set of 18 safeguard groups designed to defend against the most common cyberattacks. Implementation Groups (IG1, IG2, IG3) tailor the controls to organizational size and risk. The controls are organized from basic hygiene to advanced defensive measures.' },
  { id: 'fc028', domainId: 1, front: 'Change Management in Security', back: 'A formal process that ensures changes to systems are reviewed, approved, tested, and documented before deployment. Key components include a change request, impact analysis, approval board (CAB), rollback plan, and post-implementation review. Change management prevents unauthorized or poorly tested changes from creating vulnerabilities.' },
  { id: 'fc029', domainId: 1, front: 'Non-repudiation', back: 'The assurance that a party cannot deny having performed an action (sent a message, signed a document, authorized a transaction). Digital signatures using asymmetric cryptography are the primary technical mechanism for non-repudiation. Audit logs also support non-repudiation by timestamping actions.' },
  { id: 'fc030', domainId: 1, front: 'Confusion vs. Diffusion (cryptographic principles)', back: 'Confusion obscures the relationship between plaintext and ciphertext (achieved through substitution). Diffusion spreads the influence of each plaintext bit across the ciphertext (achieved through permutation/transposition). Both properties, articulated by Claude Shannon, are essential to strong symmetric ciphers like AES.' },
  { id: 'fc031', domainId: 1, front: 'Key Stretching', back: 'A technique that makes weak keys (e.g., passwords) harder to brute force by running them through a computationally expensive algorithm many times. Common algorithms: PBKDF2, bcrypt, scrypt, Argon2. Salting adds random data before stretching to prevent rainbow table attacks.' },
  { id: 'fc032', domainId: 1, front: 'Salting (cryptography)', back: 'Adding a unique random value (salt) to each password before hashing so that identical passwords produce different hash values. Salts prevent pre-computed rainbow table attacks and ensure that compromising one hashed password does not reveal others. Salts are stored in plaintext alongside the hash.' },
  { id: 'fc033', domainId: 1, front: 'Perfect Forward Secrecy (PFS)', back: 'A property of key exchange protocols that generates a new, ephemeral session key for each session. If a server\'s long-term private key is later compromised, past session traffic cannot be decrypted. PFS is achieved with ephemeral Diffie-Hellman (DHE/ECDHE) and is required in TLS 1.3.' },
  { id: 'fc034', domainId: 1, front: 'Steganography', back: 'The practice of hiding secret data within ordinary, non-secret files or messages — for example, embedding text within an image\'s pixel data. Unlike encryption, steganography conceals the existence of the message. It can be used by threat actors to exfiltrate data or by defenders to watermark files.' },
  { id: 'fc035', domainId: 1, front: 'Obfuscation', back: 'Making something difficult to understand while retaining its functionality. In security, obfuscation is used by attackers to hide malware logic from analysis and by defenders to protect intellectual property. Obfuscation alone is not a security control because determined attackers can deobfuscate with sufficient effort.' },
  { id: 'fc036', domainId: 1, front: 'Security Through Obscurity', back: 'Relying on secrecy of design or implementation as the primary security mechanism. This is considered a weak approach because it fails once the secret is discovered. Security through obscurity can supplement stronger controls but should never replace them.' },

  // ─── Domain 2: Threats, Vulnerabilities & Mitigations (~66 cards) ──────────

  { id: 'fc037', domainId: 2, front: 'Nation-State Threat Actor', back: 'Government-sponsored or government-directed groups that conduct cyberattacks for political, military, or economic objectives. Nation-state actors typically have extensive resources, advanced tooling (APTs), and long-term patient campaigns. Examples include Cozy Bear (Russia) and APT41 (China). Their attacks often target critical infrastructure.' },
  { id: 'fc038', domainId: 2, front: 'Hacktivist', back: 'A threat actor motivated by political, social, or ideological causes rather than financial gain. Hacktivists often conduct DDoS attacks, website defacement, or data exposure (doxing) to draw attention to causes. Anonymous is a well-known hacktivist collective. Their skill levels vary widely.' },
  { id: 'fc039', domainId: 2, front: 'Cybercriminal / Organized Crime', back: 'Financially motivated threat actors who may operate as loose collectives or structured criminal enterprises. Common activities include ransomware deployment, banking trojans, identity theft, and selling stolen credentials on dark web markets. They are increasingly offering Ransomware-as-a-Service (RaaS) to lower-skilled affiliates.' },
  { id: 'fc040', domainId: 2, front: 'Script Kiddie', back: 'An unskilled threat actor who uses pre-made tools, scripts, or exploit kits without understanding the underlying technology. Although their technical skills are low, they can still cause significant harm by deploying powerful automated tools. Defending against them requires basic hygiene: patching and strong authentication.' },
  { id: 'fc041', domainId: 2, front: 'Insider Threat', back: 'A threat that originates from within the organization — employees, contractors, or partners who misuse their legitimate access. Insider threats may be malicious (sabotage, data theft) or unintentional (accidental disclosure, misconfiguration). Detection relies on user behavior analytics (UBA), least privilege, and separation of duties.' },
  { id: 'fc042', domainId: 2, front: 'Advanced Persistent Threat (APT)', back: 'A sophisticated, stealthy, and long-duration attack campaign typically conducted by nation-state or state-sponsored actors. APTs use custom malware, zero-day exploits, and living-off-the-land techniques to maintain persistent access while avoiding detection. The goal is usually espionage or pre-positioning for future disruption.' },
  { id: 'fc043', domainId: 2, front: 'Phishing', back: 'A social engineering attack delivered via email that tricks recipients into clicking malicious links, opening malware attachments, or entering credentials on fake websites. Phishing is the most common initial access vector in breaches. Mitigations include email filtering, user training, MFA, and SPF/DKIM/DMARC.' },
  { id: 'fc044', domainId: 2, front: 'Spear Phishing', back: 'A targeted phishing attack customized for a specific individual or organization using personal details gathered through OSINT. Because the message appears relevant and legitimate, spear phishing has higher click rates than generic phishing. It is commonly used in APT campaigns to gain initial access.' },
  { id: 'fc045', domainId: 2, front: 'Whaling', back: 'A spear phishing attack that specifically targets high-value individuals such as C-suite executives, board members, or senior government officials. Attackers impersonate trusted parties and may request large wire transfers (Business Email Compromise) or sensitive information. Executive awareness training is a key mitigation.' },
  { id: 'fc046', domainId: 2, front: 'Vishing', back: 'Voice phishing — a social engineering attack conducted over telephone calls or VoIP. Attackers impersonate technical support, IRS agents, bank representatives, or other trusted entities. Caller ID spoofing makes calls appear legitimate. Training employees to verify caller identity through official channels is essential.' },
  { id: 'fc047', domainId: 2, front: 'Smishing', back: 'SMS phishing — social engineering attacks delivered via text messages containing malicious links or instructions to call fraudulent numbers. Smishing is effective because people tend to trust SMS and often click links on mobile devices without scrutinizing URLs. User awareness and mobile security policies are key defenses.' },
  { id: 'fc048', domainId: 2, front: 'Business Email Compromise (BEC)', back: 'An attack where criminals impersonate executives or trusted vendors via email to deceive employees into transferring funds or sensitive data. BEC does not require malware — it relies purely on social engineering and email spoofing. Strong email authentication (SPF/DKIM/DMARC) and out-of-band wire-transfer verification are critical mitigations.' },
  { id: 'fc049', domainId: 2, front: 'Pretexting', back: 'A social engineering technique where the attacker fabricates a believable scenario (pretext) to manipulate the target into providing information or access. Examples include impersonating IT staff, auditors, or new employees. Pretexting relies on research and psychological manipulation rather than technical exploits.' },
  { id: 'fc050', domainId: 2, front: 'Baiting', back: 'A social engineering attack that entices victims with something desirable — such as leaving infected USB drives in parking lots labeled "Salary Data" or offering free downloads containing malware. The victim\'s curiosity or greed becomes the attack vector. USB port lockdown and user training mitigate baiting.' },
  { id: 'fc051', domainId: 2, front: 'Quid Pro Quo Attack', back: 'A social engineering attack where the attacker offers a service in exchange for information. A common scenario is an attacker posing as IT support offering to fix a problem in exchange for login credentials. It exploits the reciprocity principle of human psychology.' },
  { id: 'fc052', domainId: 2, front: 'Tailgating / Piggybacking', back: 'Physically following an authorized person through a secured door without using credentials. Tailgating is unauthorized; piggybacking is with the authorized person\'s (often unwitting) consent. Mitigations include security guards, mantraps (airlock entrances), badge-activated turnstiles, and employee training.' },
  { id: 'fc053', domainId: 2, front: 'Ransomware', back: 'Malware that encrypts victim files or systems and demands payment (usually cryptocurrency) for the decryption key. Modern ransomware operators also exfiltrate data and threaten public release (double extortion). Mitigations: offline backups, endpoint detection, network segmentation, and patching. Never pay without assessing the impact.' },
  { id: 'fc054', domainId: 2, front: 'Trojan Horse', back: 'Malware disguised as legitimate or desirable software. Unlike viruses and worms, Trojans do not self-replicate — they rely on users executing them. Once installed, Trojans can create backdoors, steal data, or download additional malware. Verified software sources and application allow-listing reduce Trojan risk.' },
  { id: 'fc055', domainId: 2, front: 'Rootkit', back: 'Malware designed to gain root/administrator-level access and hide its presence from the OS, security tools, and users by subverting kernel-level functions. Rootkits are extremely difficult to detect and remove without reinstalling the OS. Secure Boot, UEFI firmware integrity, and memory integrity checks help prevent rootkits.' },
  { id: 'fc056', domainId: 2, front: 'Worm', back: 'Self-replicating malware that spreads across networks without requiring user interaction or a host file. Worms exploit vulnerabilities in network services to propagate, consuming bandwidth and potentially deploying payloads. WannaCry and NotPetya are famous examples. Patching and network segmentation are primary defenses.' },
  { id: 'fc057', domainId: 2, front: 'Spyware', back: 'Malware that secretly monitors user activity — keystrokes, screen captures, browsing history, credentials — and transmits the data to the attacker. Often bundled with legitimate-looking free software (adware/spyware bundles). Endpoint protection, browser extensions, and strict software policies help prevent spyware.' },
  { id: 'fc058', domainId: 2, front: 'Keylogger', back: 'A type of spyware that records every keystroke made on a keyboard to capture credentials, PINs, and sensitive information. Keyloggers can be software-based (malware) or hardware-based (USB/PS2 device inserted between keyboard and computer). MFA mitigates credential theft even if a keylogger captures the password.' },
  { id: 'fc059', domainId: 2, front: 'Botnet', back: 'A network of compromised computers (bots/zombies) controlled by an attacker via a Command and Control (C2) server. Botnets are used for DDoS attacks, spam campaigns, credential stuffing, and cryptocurrency mining. Sinkholing redirects C2 traffic to a controlled server to neutralize infected hosts.' },
  { id: 'fc060', domainId: 2, front: 'Command and Control (C2)', back: 'The infrastructure used by attackers to remotely communicate with and issue commands to compromised systems (bots, implants). C2 channels commonly use HTTP/HTTPS, DNS, or social media platforms to blend with legitimate traffic. DNS sinkholing and threat intelligence feeds help detect and block C2 communication.' },
  { id: 'fc061', domainId: 2, front: 'Fileless Malware', back: 'Malware that operates entirely in memory and does not write traditional executable files to disk, making it difficult for file-based antivirus to detect. It leverages legitimate system tools like PowerShell, WMI, and LOLBins (Living Off the Land Binaries). Behavioral analytics and memory scanning are required to detect fileless attacks.' },
  { id: 'fc062', domainId: 2, front: 'Logic Bomb', back: 'Malicious code embedded in legitimate software that triggers when specific conditions are met — such as a particular date, user action, or file deletion. Logic bombs are often planted by disgruntled insiders. Code reviews, change management, and separation of duties help prevent and detect them.' },
  { id: 'fc063', domainId: 2, front: 'Zero-Day Vulnerability', back: 'A software vulnerability that is unknown to the vendor and therefore has no patch available. Attackers who discover zero-days can exploit them without risk of a patch blocking the attack. Mitigations include intrusion prevention systems, application allowlisting, and segmentation while awaiting vendor patches.' },
  { id: 'fc064', domainId: 2, front: 'CVE (Common Vulnerabilities and Exposures)', back: 'A publicly maintained dictionary of known cybersecurity vulnerabilities, each assigned a unique identifier (e.g., CVE-2021-44228 for Log4Shell). CVEs are published by MITRE and the National Vulnerability Database (NVD). They allow organizations, vendors, and researchers to communicate about specific vulnerabilities using a common reference.' },
  { id: 'fc065', domainId: 2, front: 'CVSS (Common Vulnerability Scoring System)', back: 'A framework that provides a standardized numerical score (0–10) representing the severity of a vulnerability. CVSS v3.1 evaluates base metrics (exploitability, impact), temporal metrics (exploit availability, patch), and environmental metrics (asset importance). Scores help organizations prioritize remediation efforts.' },
  { id: 'fc066', domainId: 2, front: 'Vulnerability Scanning', back: 'Automated scanning of systems and networks to identify known vulnerabilities, misconfigurations, and missing patches without exploiting them. Common tools: Nessus, Qualys, OpenVAS. Unlike penetration testing, vulnerability scanning is non-destructive and can run frequently. Results must be acted on promptly to reduce exposure.' },
  { id: 'fc067', domainId: 2, front: 'Penetration Testing', back: 'An authorized, simulated cyberattack against an organization\'s systems to identify exploitable vulnerabilities before real attackers do. Pen tests go beyond scanning by actively exploiting findings. Phases: reconnaissance, scanning, exploitation, post-exploitation, and reporting. Output is a prioritized remediation report.' },
  { id: 'fc068', domainId: 2, front: 'Black Box vs. White Box vs. Gray Box Testing', back: 'Black box testers have no prior knowledge of the target (simulates an external attacker). White box testers have full knowledge — source code, architecture, credentials (simulates an insider). Gray box is a hybrid where testers have partial information. Each approach reveals different vulnerability types.' },
  { id: 'fc069', domainId: 2, front: 'OSINT (Open Source Intelligence)', back: 'The collection and analysis of publicly available information from the internet, social media, public records, WHOIS, Shodan, and other sources to gather intelligence about a target. Attackers use OSINT in reconnaissance; defenders use it to discover their own exposed information and reduce attack surface.' },
  { id: 'fc070', domainId: 2, front: 'Indicator of Compromise (IoC)', back: 'Forensic evidence that a security incident has already occurred — for example, a known malware hash, a C2 IP address, an unusual registry key, or an anomalous outbound connection. IoCs are reactive (incident already happened). Sharing IoCs via threat intelligence platforms like MISP helps organizations detect similar attacks.' },
  { id: 'fc071', domainId: 2, front: 'Indicator of Attack (IoA)', back: 'Evidence of attacker behavior or intent that suggests an attack is in progress, even without known malware signatures. IoAs are behavior-based and proactive — for example, a PowerShell process spawned by a Word document. IoAs enable earlier detection than IoC-based approaches.' },
  { id: 'fc072', domainId: 2, front: 'Attack Surface', back: 'The total set of entry points and potential vulnerabilities an attacker could use to gain unauthorized access to a system or organization. Includes network interfaces, APIs, user accounts, third-party integrations, physical access points, and social engineering vectors. Reducing attack surface is a fundamental security strategy.' },
  { id: 'fc073', domainId: 2, front: 'SQL Injection (SQLi)', back: 'An injection attack where malicious SQL statements are inserted into an application input field and executed by the database. Successful SQLi can expose, modify, or delete database contents, bypass authentication, or execute OS commands. Prevention: parameterized queries/prepared statements, input validation, least-privilege DB accounts.' },
  { id: 'fc074', domainId: 2, front: 'Cross-Site Scripting (XSS)', back: 'An injection attack where malicious scripts are injected into web pages viewed by other users. Reflected XSS is delivered via a URL; stored XSS is persisted in a database. XSS can steal session cookies, redirect users, or perform actions on their behalf. Prevention: output encoding, Content Security Policy (CSP).' },
  { id: 'fc075', domainId: 2, front: 'Cross-Site Request Forgery (CSRF)', back: 'An attack that tricks an authenticated user\'s browser into making unauthorized requests to a web application. Because the browser automatically includes session cookies, the server sees the request as legitimate. Prevention: CSRF tokens (synchronizer tokens), SameSite cookie attribute, and re-authentication for sensitive actions.' },
  { id: 'fc076', domainId: 2, front: 'Buffer Overflow', back: 'A vulnerability where a program writes more data to a buffer than it can hold, overwriting adjacent memory. Attackers can overwrite the return address to redirect execution to malicious shellcode. Mitigations: ASLR (Address Space Layout Randomization), DEP/NX (non-executable memory), stack canaries, and secure coding practices.' },
  { id: 'fc077', domainId: 2, front: 'DDoS (Distributed Denial of Service)', back: 'An attack that overwhelms a target system or network with traffic from many sources (botnet) to make it unavailable to legitimate users. Types include volumetric (bandwidth exhaustion), protocol (SYN flood), and application layer (HTTP flood) attacks. Mitigations: rate limiting, CDNs, anycast diffusion, and DDoS scrubbing services.' },
  { id: 'fc078', domainId: 2, front: 'Man-in-the-Middle (MitM) Attack', back: 'An attack where the adversary secretly intercepts and potentially alters communications between two parties who believe they are communicating directly. Common MitM techniques: ARP poisoning, rogue Wi-Fi AP, SSL stripping. Mitigations: mutual TLS, certificate pinning, HSTS, and VPNs on untrusted networks.' },
  { id: 'fc079', domainId: 2, front: 'ARP Poisoning / Spoofing', back: 'An attacker sends forged ARP (Address Resolution Protocol) replies to associate their MAC address with a legitimate IP address, causing traffic to be redirected through the attacker\'s machine. It enables MitM attacks on local networks. Dynamic ARP Inspection (DAI) on switches and static ARP entries mitigate this attack.' },
  { id: 'fc080', domainId: 2, front: 'DNS Poisoning / Cache Poisoning', back: 'Injecting false DNS records into a resolver\'s cache so that DNS queries for a legitimate domain return the attacker\'s IP address, redirecting users to malicious sites. DNSSEC (DNS Security Extensions) digitally signs DNS records to prevent poisoning. Monitoring for unexpected DNS record changes is also important.' },
  { id: 'fc081', domainId: 2, front: 'Credential Stuffing', back: 'Using large lists of stolen username/password pairs (from prior breaches) to attempt automated logins across many services, exploiting password reuse. Mitigations: MFA, rate limiting, account lockout policies, CAPTCHA, and monitoring for login anomalies. Password managers encourage unique passwords per site.' },
  { id: 'fc082', domainId: 2, front: 'Password Spraying', back: 'Attempting a small set of commonly used passwords (e.g., "Winter2024!") against a large number of accounts to avoid triggering lockout thresholds. Unlike brute force, which attacks one account with many passwords, spraying attacks many accounts with few passwords. Detection: monitoring for distributed failed logins across accounts.' },
  { id: 'fc083', domainId: 2, front: 'Brute Force Attack', back: 'Systematically trying every possible password or key combination until the correct one is found. Online brute force is slowed by lockout policies and rate limiting; offline attacks against stolen hashes are limited only by computational power. Strong, long passwords and hashing with bcrypt/Argon2 mitigate offline brute force.' },
  { id: 'fc084', domainId: 2, front: 'Rainbow Table Attack', back: 'A precomputed attack where an attacker looks up hashed passwords in a table of hash-to-plaintext mappings, bypassing the need to compute hashes during the attack. Salting defeats rainbow tables because each password\'s unique salt makes precomputation impractical.' },
  { id: 'fc085', domainId: 2, front: 'Supply Chain Attack', back: 'An attack that targets less-secure elements in the software or hardware supply chain — for example, compromising a software update mechanism (SolarWinds), a library (XZ Utils), or hardware before delivery. Mitigations: software bill of materials (SBOM), code signing, vendor risk assessments, and integrity verification.' },
  { id: 'fc086', domainId: 2, front: 'Watering Hole Attack', back: 'An attacker compromises a website frequently visited by the intended targets and injects malware or a drive-by exploit. Named after the predator tactic of waiting at a watering hole. Defenses include browser isolation, content filtering, and promptly patching browsers and plugins.' },
  { id: 'fc087', domainId: 2, front: 'Drive-By Download', back: 'Malware that is automatically downloaded and executed when a user visits a compromised or malicious website, without any explicit user action beyond visiting the page. Exploits browser or plugin vulnerabilities. Mitigations: keeping browsers and plugins patched, ad blockers, script blockers, and web filtering.' },
  { id: 'fc088', domainId: 2, front: 'Typosquatting / URL Hijacking', back: 'Registering domain names that are common misspellings or slight variations of legitimate sites (e.g., "gooogle.com") to capture users who make typos. Used for phishing, malware distribution, or advertising. Organizations can defensively register common typo variants of their own domain.' },
  { id: 'fc089', domainId: 2, front: 'Threat Intelligence', back: 'The collection, analysis, and application of information about current and potential threats to an organization. Tactical intelligence includes IoCs; operational intelligence covers attacker TTPs; strategic intelligence informs risk decisions at the leadership level. Sources include ISACs, vendor feeds, and government agencies (CISA, FBI).' },
  { id: 'fc090', domainId: 2, front: 'MITRE ATT&CK Framework', back: 'A globally accessible knowledge base of adversary tactics and techniques based on real-world observations, organized into a matrix. It covers tactics from initial access through exfiltration and impact. Security teams use ATT&CK for threat modeling, detection engineering, red/blue team exercises, and gap analysis.' },
  { id: 'fc091', domainId: 2, front: 'Vulnerability vs. Threat vs. Risk', back: 'A vulnerability is a weakness in a system. A threat is a potential event or actor that could exploit that weakness. Risk is the likelihood that a threat exploits a vulnerability multiplied by the resulting impact. Risk = Threat × Vulnerability × Impact. All three must exist for risk to be present.' },
  { id: 'fc092', domainId: 2, front: 'Dumpster Diving', back: 'Searching through an organization\'s trash for sensitive information such as printed documents, discarded hardware, or sticky notes with passwords. Despite being a low-tech attack, it can yield valuable information. Mitigations: shredding documents, degaussing media, and clear-desk policies.' },
  { id: 'fc093', domainId: 2, front: 'Shoulder Surfing', back: 'Observing someone\'s screen or keyboard to capture sensitive information such as passwords, PINs, or confidential data. Can occur in person or through cameras. Mitigations: privacy screens, screen locks on unattended systems, and positioning screens away from public sightlines.' },
  { id: 'fc094', domainId: 2, front: 'Evil Twin Attack', back: 'A rogue wireless access point configured to mimic a legitimate network\'s SSID and signal strength, tricking users into connecting. Once connected, the attacker can intercept or manipulate traffic. Mitigations: use 802.1X authentication for Wi-Fi, VPN on all untrusted networks, and wireless intrusion prevention systems (WIPS).' },
  { id: 'fc095', domainId: 2, front: 'Replay Attack', back: 'An attacker captures legitimate authentication tokens or messages and retransmits them to impersonate the original sender. Defenses include timestamps with short validity windows, nonces (random values), and sequence numbers that ensure each authentication token is unique and single-use.' },
  { id: 'fc096', domainId: 2, front: 'On-Path Attack (formerly MitM)', back: 'The updated CompTIA SY0-701 term for what was traditionally called a Man-in-the-Middle (MitM) attack. An on-path attacker positions themselves between two communicating parties to intercept, read, or modify traffic in transit. Prevention includes mutual authentication, TLS, and network monitoring.' },
  { id: 'fc097', domainId: 2, front: 'Cryptojacking', back: 'Unauthorized use of a victim\'s computing resources to mine cryptocurrency. Attackers deliver mining scripts via malicious websites (in-browser) or malware. Signs include unexpected CPU/GPU spikes and high electricity usage. Endpoint detection tools, browser script blocking, and network monitoring help detect cryptojacking.' },
  { id: 'fc098', domainId: 2, front: 'Side-Channel Attack', back: 'An attack that exploits information leaked through physical implementation of a system — such as power consumption, electromagnetic emissions, timing variations, or acoustic emissions — rather than mathematical weaknesses in the algorithm. Meltdown and Spectre are famous CPU side-channel vulnerabilities.' },
  { id: 'fc099', domainId: 2, front: 'Injection Attack (general)', back: 'A broad category of attacks where malicious data is sent to an interpreter as part of a command or query, causing unintended behavior. Includes SQL injection, command injection, LDAP injection, and XML injection. Input validation, parameterized queries, and the principle of least privilege for interpreters are the primary defenses.' },
  { id: 'fc100', domainId: 2, front: 'Privilege Escalation', back: 'An attack where an adversary gains higher privileges than initially granted — either vertically (from user to admin) or horizontally (accessing another user\'s resources at the same privilege level). Common techniques: exploiting unpatched vulnerabilities, misconfigured sudo rules, or weak service account permissions.' },
  { id: 'fc101', domainId: 2, front: 'Lateral Movement', back: 'Techniques used by attackers to progressively move through a network after gaining initial access, seeking higher-value targets. Methods include Pass-the-Hash, Pass-the-Ticket, SMB exploitation, and remote desktop. Mitigations: network segmentation, MFA, privileged access workstations (PAWs), and behavioral monitoring.' },
  { id: 'fc102', domainId: 2, front: 'Pass-the-Hash Attack', back: 'An attack where an adversary captures NTLM password hash values from memory (e.g., using Mimikatz) and uses them directly to authenticate without knowing the plaintext password. Mitigations: Windows Credential Guard, disabling NTLM where possible, and restricting local administrator accounts.' },

  // ─── Domain 3: Security Architecture (~54 cards) ───────────────────────────

  { id: 'fc103', domainId: 3, front: 'VLAN (Virtual Local Area Network)', back: 'A logical network segment created on a switch that separates traffic at Layer 2 regardless of physical topology. VLANs limit broadcast domains, contain lateral movement, and enforce network segmentation. Inter-VLAN routing requires a router or Layer 3 switch, providing a control point for security policy.' },
  { id: 'fc104', domainId: 3, front: 'DMZ (Demilitarized Zone)', back: 'A network segment that sits between the public internet and the internal trusted network, hosting publicly accessible services such as web servers, email servers, and DNS resolvers. A firewall (or two firewalls) controls traffic entering and leaving the DMZ, protecting internal resources from direct internet exposure.' },
  { id: 'fc105', domainId: 3, front: 'IaaS (Infrastructure as a Service)', back: 'A cloud model that provides virtualized computing infrastructure — VMs, storage, and networking — over the internet. The cloud provider manages physical hardware, hypervisors, and data center facilities. The customer manages the OS, middleware, runtime, applications, and data. Examples: AWS EC2, Azure VMs, GCP Compute Engine.' },
  { id: 'fc106', domainId: 3, front: 'PaaS (Platform as a Service)', back: 'A cloud model that provides a managed platform for developing, running, and managing applications. The provider manages infrastructure, OS, runtime, and middleware; the customer manages applications and data. Examples: AWS Elastic Beanstalk, Google App Engine, Azure App Service. Reduces operational overhead for developers.' },
  { id: 'fc107', domainId: 3, front: 'SaaS (Software as a Service)', back: 'A cloud model that delivers fully managed software applications over the internet on a subscription basis. The provider manages everything — infrastructure through the application itself. The customer manages only data and user access. Examples: Microsoft 365, Salesforce, Google Workspace.' },
  { id: 'fc108', domainId: 3, front: 'Shared Responsibility Model', back: 'Defines which security responsibilities belong to the cloud provider and which belong to the customer. Generally, the provider is responsible for security "of" the cloud (physical, hypervisor, network); the customer is responsible for security "in" the cloud (data, IAM, application, OS in IaaS). The division shifts based on service model (IaaS/PaaS/SaaS).' },
  { id: 'fc109', domainId: 3, front: 'Public Cloud', back: 'Cloud infrastructure owned and operated by a third-party provider, shared across multiple customers (multi-tenancy). Resources are accessed over the public internet. Public cloud is cost-effective and scalable but requires trust in the provider\'s security controls and separation of tenant data.' },
  { id: 'fc110', domainId: 3, front: 'Private Cloud', back: 'Cloud infrastructure dedicated exclusively to a single organization, either on-premises or hosted by a third party. Offers more control, customization, and data sovereignty than public cloud, but at higher cost and with greater operational overhead. Preferred by organizations with strict compliance or data residency requirements.' },
  { id: 'fc111', domainId: 3, front: 'Hybrid Cloud', back: 'A combination of private and public cloud environments connected by technology that allows data and applications to be shared between them. Provides flexibility to run sensitive workloads on private infrastructure while bursting to public cloud for scalability. Requires consistent security policy across both environments.' },
  { id: 'fc112', domainId: 3, front: 'Virtualization Security', back: 'Virtualization uses a hypervisor (Type 1: bare metal; Type 2: hosted) to run multiple virtual machines on shared hardware. Security concerns include VM escape (breaking out of the VM to the hypervisor), hyperjacking (compromising the hypervisor), and resource contention. Keeping hypervisors patched and using separate management networks are essential.' },
  { id: 'fc113', domainId: 3, front: 'Containerization (Docker/Kubernetes)', back: 'Containers package an application with its dependencies and share the host OS kernel, making them lighter than VMs. Security concerns: container escape, insecure images, excessive privileges, and shared kernel vulnerabilities. Mitigations: run containers as non-root, scan images for vulnerabilities, use network policies, and apply pod security standards in Kubernetes.' },
  { id: 'fc114', domainId: 3, front: 'Serverless Computing', back: 'A cloud execution model where the provider dynamically manages server provisioning and scaling. Developers deploy functions (FaaS) without managing servers. Security considerations: function misconfiguration, insecure dependencies, overpermissive IAM roles, and cold-start injection attacks. The shared responsibility model still applies.' },
  { id: 'fc115', domainId: 3, front: 'SD-WAN (Software-Defined Wide Area Network)', back: 'A technology that uses software to control and optimize connectivity across geographically distributed locations, abstracting the underlying network hardware. SD-WAN can route traffic over multiple links (MPLS, broadband, LTE) based on policy. Security features vary by vendor; a cloud-based security layer is often added (SASE).' },
  { id: 'fc116', domainId: 3, front: 'SASE (Secure Access Service Edge)', back: 'A cloud-delivered architecture that converges wide-area networking (SD-WAN) and comprehensive network security services (CASB, SWG, ZTNA, FWaaS) into a single cloud service. SASE enforces consistent security policy regardless of user location, supporting remote and hybrid workforces.' },
  { id: 'fc117', domainId: 3, front: 'ZTNA (Zero Trust Network Access)', back: 'A security model that replaces traditional VPNs by granting application-specific access based on continuous identity verification and device posture rather than network-level access. Users are never on the corporate network by default. ZTNA is a core component of SASE and Zero Trust Architecture.' },
  { id: 'fc118', domainId: 3, front: 'IAM (Identity and Access Management)', back: 'A framework of policies and technologies that ensure only the right entities (users, services, devices) have access to the right resources at the right time. IAM components include directories (LDAP/AD), authentication systems, authorization policies, and provisioning/deprovisioning workflows. Proper IAM is foundational to Zero Trust.' },
  { id: 'fc119', domainId: 3, front: 'PAM (Privileged Access Management)', back: 'A solution that controls, monitors, and audits access to privileged accounts (root, administrator, service accounts). PAM features include just-in-time (JIT) access, session recording, password vaulting, and approval workflows. Privileged accounts are high-value targets; PAM significantly reduces insider and external threat risk.' },
  { id: 'fc120', domainId: 3, front: 'TLS (Transport Layer Security)', back: 'A cryptographic protocol that provides confidentiality, integrity, and authentication for data in transit. TLS 1.3 is the current standard, mandating ECDHE for key exchange (ensuring PFS) and removing legacy cipher suites. TLS is used to secure HTTPS, SMTP, LDAPS, and many other protocols.' },
  { id: 'fc121', domainId: 3, front: 'SSH (Secure Shell)', back: 'A cryptographic network protocol for operating remote command-line sessions and transferring files securely. SSH uses asymmetric keys for authentication (preferred over passwords) and symmetric encryption for the session. SSH key management (rotating keys, auditing authorized_keys) is an important operational security concern.' },
  { id: 'fc122', domainId: 3, front: 'SFTP vs. FTPS', back: 'SFTP (SSH File Transfer Protocol) tunnels file transfers over SSH, using port 22. FTPS (FTP Secure) adds TLS encryption to traditional FTP, typically using ports 21 (control) and 989/990 (data). Both are secure alternatives to plaintext FTP. SFTP is simpler to firewall because it uses a single port.' },
  { id: 'fc123', domainId: 3, front: 'IPsec', back: 'A suite of protocols that authenticate and encrypt IP packets at Layer 3. IPsec operates in tunnel mode (encrypts entire packet, used in site-to-site VPNs) or transport mode (encrypts only payload, used for host-to-host). Key protocols: AH (authentication only), ESP (encryption + optional authentication), IKE (key exchange).' },
  { id: 'fc124', domainId: 3, front: 'VPN (Virtual Private Network)', back: 'An encrypted tunnel over an untrusted network that allows remote users or sites to securely communicate as if on a private network. Site-to-site VPNs connect entire networks; remote-access VPNs connect individual users. Split tunneling allows only VPN-destined traffic through the tunnel; full tunnel routes all traffic.' },
  { id: 'fc125', domainId: 3, front: 'Network Access Control (NAC)', back: 'A security solution that enforces policy-based access for devices connecting to a network. NAC assesses device compliance (patch status, AV, certificate) before granting access, placing non-compliant devices in a quarantine VLAN for remediation. 802.1X is the standard protocol for NAC on wired and wireless networks.' },
  { id: 'fc126', domainId: 3, front: '802.1X Authentication', back: 'An IEEE standard for port-based network access control that requires devices to authenticate (via EAP methods) to a RADIUS server before being allowed on the network. Components: supplicant (device), authenticator (switch/AP), and authentication server (RADIUS). It prevents unauthorized devices from connecting to the network.' },
  { id: 'fc127', domainId: 3, front: 'Microsegmentation', back: 'Dividing a network into very small, isolated segments and enforcing granular security policy between each segment. Unlike traditional VLAN segmentation, microsegmentation typically operates at the workload level using software-defined networking. It limits lateral movement by containing attackers within a single microsegment.' },
  { id: 'fc128', domainId: 3, front: 'Air Gap', back: 'A physical isolation technique where a secure computer or network has no direct or indirect connection to insecure networks or the internet. Used in high-security environments like industrial control systems, nuclear facilities, and classified networks. Air gaps can still be compromised via removable media (USB) or RF side channels.' },
  { id: 'fc129', domainId: 3, front: 'Proxy Server', back: 'An intermediary server that sits between clients and servers, forwarding requests on the client\'s behalf. Forward proxies control outbound internet access and can enforce content filtering, caching, and SSL inspection. Reverse proxies sit in front of servers, providing load balancing, SSL termination, and WAF functionality.' },
  { id: 'fc130', domainId: 3, front: 'Load Balancer', back: 'Distributes incoming network traffic across multiple servers to ensure no single server is overwhelmed, improving availability and performance. Load balancers can perform SSL offloading, health checking, and session persistence. They also provide resilience — if one server fails, traffic is redirected to healthy servers.' },
  { id: 'fc131', domainId: 3, front: 'CDN (Content Delivery Network)', back: 'A distributed network of servers that caches and delivers web content from nodes geographically close to users, reducing latency and absorbing traffic spikes. CDNs also provide DDoS mitigation by distributing attack traffic across their global network. Major providers: Cloudflare, Akamai, AWS CloudFront.' },
  { id: 'fc132', domainId: 3, front: 'HSM (Hardware Security Module)', back: 'A dedicated physical device that generates, stores, and manages cryptographic keys in a tamper-resistant hardware environment. HSMs are used for CA root key storage, code signing, payment processing (PCI-DSS), and TLS certificate private keys. They ensure keys are never exposed in plaintext outside the device.' },
  { id: 'fc133', domainId: 3, front: 'TPM (Trusted Platform Module)', back: 'A secure cryptoprocessor chip on a motherboard that stores cryptographic keys, certificates, and measurements for platform integrity. TPM enables Secure Boot, disk encryption key protection (BitLocker), and remote attestation. TPM 2.0 is required for Windows 11 and modern enterprise security features.' },
  { id: 'fc134', domainId: 3, front: 'Secure Boot', back: 'A UEFI firmware security feature that ensures only digitally signed, trusted software (bootloader, OS kernel) is loaded during the boot process. It prevents rootkits and bootkits from loading before the OS. Secure Boot requires the firmware to hold a database of trusted signing certificates.' },
  { id: 'fc135', domainId: 3, front: 'Full Disk Encryption (FDE)', back: 'Encrypts all data on a storage device so that it cannot be accessed without proper authentication. BitLocker (Windows) and FileVault (macOS) are common FDE implementations. FDE protects data at rest against physical theft of devices. The encryption key is often stored in the TPM and released after successful authentication.' },
  { id: 'fc136', domainId: 3, front: 'Data at Rest, in Transit, in Use', back: 'The three states of data requiring protection. At rest: stored data on disk, databases, backups — protected by encryption and access controls. In transit: data moving over networks — protected by TLS/IPsec. In use: data being actively processed in memory — the hardest to protect; technologies like Trusted Execution Environments (TEE) and homomorphic encryption address this.' },
  { id: 'fc137', domainId: 3, front: 'CASB (Cloud Access Security Broker)', back: 'A security policy enforcement point between cloud service consumers and cloud providers. CASBs provide visibility into cloud app usage (shadow IT), enforce data loss prevention policies, detect threats, and ensure compliance. Can be implemented as API-based (inline inspection) or proxy-based (real-time traffic inspection).' },
  { id: 'fc138', domainId: 3, front: 'SWG (Secure Web Gateway)', back: 'A cloud-delivered or on-premises proxy that inspects outbound web traffic to enforce acceptable use policies, block malware downloads, and prevent access to malicious sites. SWGs perform URL filtering, SSL/TLS inspection, and content analysis. They are a key component of SASE architectures.' },
  { id: 'fc139', domainId: 3, front: 'WAF (Web Application Firewall)', back: 'A specialized firewall that monitors, filters, and blocks HTTP/HTTPS traffic to and from web applications based on a rule set. WAFs protect against OWASP Top 10 attacks including SQLi, XSS, and CSRF. They can be deployed in block mode (active) or detect mode (passive/logging).' },
  { id: 'fc140', domainId: 3, front: 'NGFW (Next-Generation Firewall)', back: 'A firewall that combines traditional stateful packet inspection with application awareness (Layer 7), intrusion prevention (IPS), deep packet inspection, TLS inspection, and user identity awareness. NGFWs can identify and control applications regardless of port, making them far more effective than port-based firewalls.' },
  { id: 'fc141', domainId: 3, front: 'Stateful Firewall', back: 'Tracks the state of active network connections and allows or denies packets based on context (is this packet part of an established, legitimate session?). More secure than stateless (packet filter) firewalls because it understands connection state and can block packets that don\'t match any known session.' },
  { id: 'fc142', domainId: 3, front: 'High Availability (HA)', back: 'A system design approach that ensures continuous operation with minimal downtime through redundancy and failover. Key concepts: active-active (all nodes handle traffic) vs. active-passive (standby takes over on failure), clustering, and load balancing. HA is measured in nines: 99.999% ("five nines") = ~5 minutes downtime per year.' },
  { id: 'fc143', domainId: 3, front: 'Redundancy and Fault Tolerance', back: 'Redundancy uses duplicate components (power supplies, network links, storage) so that failure of one does not cause system failure. Fault tolerance is the ability of a system to continue operating correctly even when components fail. RAID, UPS, and geographic replication are common redundancy techniques.' },
  { id: 'fc144', domainId: 3, front: 'RAID (Redundant Array of Independent Disks)', back: 'A storage technology that combines multiple disks for performance, redundancy, or both. RAID 1 (mirror) duplicates data across two drives. RAID 5 (striping with parity) requires 3+ drives and can survive one disk failure. RAID 6 can survive two failures. RAID 0 provides performance only — no redundancy.' },
  { id: 'fc145', domainId: 3, front: 'Geographically Dispersed Data Centers', back: 'Running systems across multiple physical locations to protect against site-level disasters (fire, flood, power outage). Replication keeps data synchronized across sites. Active-active configurations allow either site to serve traffic; active-passive configurations keep one site on standby. Data sovereignty laws may restrict where data can be stored.' },
  { id: 'fc146', domainId: 3, front: 'Cryptographic Agility', back: 'The ability of a system to easily switch between cryptographic algorithms without major redesign. Cryptographically agile systems can rapidly migrate to new algorithms when existing ones are broken or deprecated (e.g., moving from SHA-1 to SHA-256, or from RSA to post-quantum algorithms). Critical for long-term security.' },
  { id: 'fc147', domainId: 3, front: 'Post-Quantum Cryptography (PQC)', back: 'Cryptographic algorithms designed to be secure against attacks by quantum computers, which can break RSA and ECC using Shor\'s algorithm. NIST finalized the first PQC standards in 2024: CRYSTALS-Kyber (key encapsulation) and CRYSTALS-Dilithium (digital signatures). Organizations should plan migration to PQC now.' },
  { id: 'fc148', domainId: 3, front: 'Secure DNS (DoH / DoT)', back: 'DNS over HTTPS (DoH) and DNS over TLS (DoT) encrypt DNS queries to prevent eavesdropping and manipulation. Traditional DNS sends queries in plaintext, exposing browsing behavior. DoH uses port 443 (harder to block); DoT uses port 853. Both protect against on-path attackers and ISP monitoring.' },
  { id: 'fc149', domainId: 3, front: 'API Security', back: 'APIs are frequent attack targets. Key security controls: authentication (API keys, OAuth 2.0, JWT), input validation, rate limiting, TLS encryption, and an API gateway for centralized policy enforcement. The OWASP API Security Top 10 identifies common API risks such as broken object-level authorization (BOLA).' },
  { id: 'fc150', domainId: 3, front: 'OAuth 2.0', back: 'An authorization framework that allows third-party applications to obtain limited access to a user\'s resources without exposing credentials. Users grant permission via an authorization server, which issues access tokens to the application. OAuth 2.0 is widely used for "Sign in with Google/Facebook" functionality.' },
  { id: 'fc151', domainId: 3, front: 'SAML (Security Assertion Markup Language)', back: 'An XML-based open standard for exchanging authentication and authorization data between an identity provider (IdP) and a service provider (SP). SAML enables SSO in enterprise environments — users authenticate once at the IdP and gain access to multiple SPs via signed assertions. Common in federated identity scenarios.' },
  { id: 'fc152', domainId: 3, front: 'Deception Technology (Honeypot)', back: 'Honeypots are decoy systems or services designed to attract, detect, and analyze attackers while recording their techniques. A honeynet is a network of honeypots. Canary tokens are lightweight deception artifacts (fake credentials, URLs) that alert when accessed. Deception technology provides high-fidelity alerts with low false positives.' },
  { id: 'fc153', domainId: 3, front: 'Software-Defined Networking (SDN)', back: 'Separates the network control plane (routing decisions) from the data plane (packet forwarding) and centralizes control in a software controller. SDN enables dynamic, programmable network configuration and granular traffic control. It simplifies microsegmentation and policy enforcement across large networks.' },
  { id: 'fc154', domainId: 3, front: 'Infrastructure as Code (IaC)', back: 'Managing and provisioning infrastructure through machine-readable configuration files rather than manual processes. IaC (Terraform, CloudFormation, Ansible) enables repeatable, auditable deployments. Security risk: misconfigurations in IaC templates propagate to production. Static analysis tools (tfsec, Checkov) scan IaC for security issues.' },
  { id: 'fc155', domainId: 3, front: 'Secure Software Development Lifecycle (SSDLC)', back: 'Integrates security activities throughout every phase of software development — requirements, design, coding, testing, deployment, and maintenance. Key activities: threat modeling, secure code reviews, SAST/DAST testing, dependency scanning, and penetration testing. "Shift left" refers to moving security earlier in the development process.' },
  { id: 'fc156', domainId: 3, front: 'SAST vs. DAST', back: 'Static Application Security Testing (SAST) analyzes source code without execution to find vulnerabilities like hardcoded credentials, injection flaws, and buffer overflows. Dynamic Application Security Testing (DAST) tests a running application by sending inputs and analyzing outputs. SAST finds issues early; DAST tests runtime behavior.' },

  // ─── Domain 4: Security Operations (~84 cards) ─────────────────────────────

  { id: 'fc157', domainId: 4, front: 'Incident Response Lifecycle (NIST SP 800-61)', back: 'NIST defines six phases: Preparation → Identification (Detection & Analysis) → Containment → Eradication → Recovery → Post-Incident Activity (Lessons Learned). Some frameworks condense to four phases (Preparation, Detection, Containment/Eradication/Recovery, Post-Incident). Preparation is the most important phase — good IR starts before the incident.' },
  { id: 'fc158', domainId: 4, front: 'Incident Response: Preparation Phase', back: 'Building the capability to respond before incidents occur. Activities include developing an IR plan, establishing an IR team, creating communication trees, acquiring tools (SIEM, forensic workstations), training staff, conducting tabletop exercises, and ensuring legal/HR/PR are aware of their roles.' },
  { id: 'fc159', domainId: 4, front: 'Incident Response: Identification Phase', back: 'Detecting and confirming that an incident has occurred. Sources include SIEM alerts, IDS/IPS, antivirus, user reports, and threat intelligence. Analysts triage events to determine if they constitute an incident, assign severity, and begin documentation. Speed is critical — early detection limits damage.' },
  { id: 'fc160', domainId: 4, front: 'Incident Response: Containment Phase', back: 'Limiting the spread and impact of the incident. Short-term containment (isolating affected systems) must happen quickly. Long-term containment involves patching or hardening systems for continued operation. Evidence preservation is critical during containment — avoid destroying forensic data.' },
  { id: 'fc161', domainId: 4, front: 'Incident Response: Eradication Phase', back: 'Removing the root cause of the incident — malware, backdoors, unauthorized accounts, and misconfigurations. Eradication must be thorough; leaving any persistence mechanism allows re-compromise. Reimaging affected systems is often safer than attempting to clean them manually.' },
  { id: 'fc162', domainId: 4, front: 'Incident Response: Recovery Phase', back: 'Restoring systems to normal operation and verifying they are clean and functional. Recovery includes restoring from backups, applying patches, resetting credentials, and monitoring for re-infection. Phased recovery starts with the most critical systems. Business stakeholders must approve the return to production.' },
  { id: 'fc163', domainId: 4, front: 'Incident Response: Post-Incident Activity (Lessons Learned)', back: 'A structured review meeting held after an incident (typically within 2 weeks) to analyze what happened, what worked, what failed, and how to prevent recurrence. Output is a report with concrete action items — updated runbooks, new detective controls, additional training. Also called an After-Action Review (AAR).' },
  { id: 'fc164', domainId: 4, front: 'Digital Forensics', back: 'The process of collecting, preserving, analyzing, and presenting digital evidence in a manner that is legally admissible. Forensic investigations must follow strict procedures to maintain evidence integrity. The chain of custody documents who handled evidence, when, and how. Hashing is used to verify evidence has not been altered.' },
  { id: 'fc165', domainId: 4, front: 'Chain of Custody', back: 'A documented, unbroken record of who collected, handled, transferred, analyzed, or had access to evidence. Every transfer of evidence must be documented with date, time, and signatures. A broken chain of custody can render evidence inadmissible in court. Write blockers prevent accidental modification during forensic acquisition.' },
  { id: 'fc166', domainId: 4, front: 'Order of Volatility', back: 'The principle that digital evidence should be collected in order of most volatile (most likely to be lost) to least volatile. Order: CPU registers/cache → RAM → network connections/ARP cache → running processes → disk storage → logs → archived media. RAM is particularly important — it contains running processes, encryption keys, and network connections.' },
  { id: 'fc167', domainId: 4, front: 'Write Blocker', back: 'A hardware or software tool that prevents any write operations to a storage device during forensic acquisition, ensuring the original evidence is not modified. Hardware write blockers are preferred for legal proceedings because they are hardware-enforced. All forensic images are verified with cryptographic hashes.' },
  { id: 'fc168', domainId: 4, front: 'SIEM (Security Information and Event Management)', back: 'A platform that aggregates, correlates, and analyzes log data from across the enterprise (firewalls, endpoints, servers, applications) in real time. SIEM provides centralized log storage, threat detection via correlation rules, dashboards, and alerting. Examples: Splunk, Microsoft Sentinel, IBM QRadar, Elastic SIEM.' },
  { id: 'fc169', domainId: 4, front: 'SOAR (Security Orchestration, Automation, and Response)', back: 'A platform that automates repetitive security tasks, orchestrates tools, and manages IR workflows (playbooks). SOAR ingests alerts from SIEM and other tools, automatically triages low-priority events, and accelerates analyst response. It reduces mean time to respond (MTTR) and analyst alert fatigue.' },
  { id: 'fc170', domainId: 4, front: 'EDR (Endpoint Detection and Response)', back: 'A security solution deployed on endpoints that continuously monitors and records activity, detects suspicious behavior, and enables rapid investigation and response. EDR goes beyond antivirus by using behavioral analytics and threat intelligence. It provides telemetry for threat hunting and forensic investigation.' },
  { id: 'fc171', domainId: 4, front: 'XDR (Extended Detection and Response)', back: 'An evolution of EDR that integrates and correlates telemetry across multiple security layers — endpoints, network, email, cloud, and identity — into a unified detection and response platform. XDR breaks down security silos, providing broader visibility and faster, more accurate threat detection than individual point solutions.' },
  { id: 'fc172', domainId: 4, front: 'IDS vs. IPS', back: 'An Intrusion Detection System (IDS) passively monitors traffic, generates alerts for suspicious activity, but does not block it. An Intrusion Prevention System (IPS) is inline, actively blocking or dropping malicious traffic in real time. IPS requires well-tuned rules to avoid blocking legitimate traffic (false positives).' },
  { id: 'fc173', domainId: 4, front: 'Signature-Based Detection', back: 'Compares observed activity (file hashes, network traffic patterns, byte sequences) against a database of known attack signatures. Highly accurate for known threats with low false positives. Blind to zero-day attacks and polymorphic malware that changes its signature. Requires frequent signature database updates.' },
  { id: 'fc174', domainId: 4, front: 'Anomaly-Based / Behavioral Detection', back: 'Establishes a baseline of normal behavior and alerts on deviations. Can detect unknown attacks and zero-days that signature-based systems miss. Requires a learning period and generates more false positives, especially in dynamic environments. Machine learning improves accuracy over time.' },
  { id: 'fc175', domainId: 4, front: 'Threat Hunting', back: 'Proactive, analyst-driven searching through security data to find hidden threats that have evaded automated detection. Threat hunters formulate hypotheses (based on threat intelligence and ATT&CK), then search logs and telemetry to confirm or deny them. It complements reactive monitoring and improves detection coverage.' },
  { id: 'fc176', domainId: 4, front: 'Log Management', back: 'The centralized collection, storage, and retention of log data from systems, applications, and network devices. Logs are essential for incident investigation, compliance, and threat detection. Key considerations: what to log, secure log transmission, tamper-proof storage, retention period (often 1 year+ for compliance), and log integrity verification.' },
  { id: 'fc177', domainId: 4, front: 'Syslog', back: 'A standard protocol (RFC 5424) for transmitting log messages across IP networks, used by network devices, servers, and applications to send event data to a central log server. Syslog messages are categorized by facility (source type) and severity (0=Emergency to 7=Debug). Encrypted syslog over TLS is used for secure transmission.' },
  { id: 'fc178', domainId: 4, front: 'Patch Management', back: 'The systematic process of identifying, acquiring, testing, and deploying software patches to fix vulnerabilities. Effective patch management includes a defined SLA for patch deployment based on severity (critical CVEs within 24-72 hours), testing in a staging environment, and maintaining an accurate software inventory.' },
  { id: 'fc179', domainId: 4, front: 'Configuration Management', back: 'Establishing and maintaining secure baseline configurations for all systems and devices. Baselines define the approved, secure state. Configuration management tools (Ansible, Puppet, Chef, SCCM) automate enforcement and detect drift. Security benchmarks (CIS Benchmarks) provide hardening guidance for common platforms.' },
  { id: 'fc180', domainId: 4, front: 'Endpoint Hardening', back: 'Reducing the attack surface of endpoint devices by disabling unnecessary services, applying CIS benchmarks, removing unneeded software, enabling host-based firewalls, configuring full disk encryption, and deploying EDR. Hardened endpoints are significantly harder to compromise and limit the impact of successful attacks.' },
  { id: 'fc181', domainId: 4, front: 'Application Allow-Listing', back: 'Only approved (whitelisted) applications are permitted to execute on endpoints. Any unapproved executable is blocked. Allow-listing is highly effective against malware and unauthorized software but requires significant initial effort to build and maintain the approved list. Tools: AppLocker, Windows Defender Application Control (WDAC).' },
  { id: 'fc182', domainId: 4, front: 'Antivirus / Anti-Malware', back: 'Software that detects, quarantines, and removes malware. Modern solutions use signature-based detection, heuristics, behavioral analysis, and cloud-based threat intelligence. Next-generation AV (NGAV) is a subset of EDR that uses ML for detection. Regular updates are essential for maintaining signature currency.' },
  { id: 'fc183', domainId: 4, front: 'Host-Based Firewall', back: 'A software firewall running on an individual endpoint that controls inbound and outbound connections to that host. Unlike network firewalls, host-based firewalls protect against lateral movement within the same network segment. Windows Firewall and iptables/nftables (Linux) are common examples.' },
  { id: 'fc184', domainId: 4, front: 'SSO (Single Sign-On)', back: 'An authentication scheme that allows users to authenticate once and gain access to multiple applications or systems without re-entering credentials. SSO reduces password fatigue and enables centralized access control. Built on protocols like SAML, OAuth 2.0/OIDC, and Kerberos. SSO infrastructure is a high-value target.' },
  { id: 'fc185', domainId: 4, front: 'Kerberos', back: 'A network authentication protocol used in Windows Active Directory that uses tickets granted by a Key Distribution Center (KDC). The KDC issues a Ticket Granting Ticket (TGT) after initial authentication; the TGT is used to request service tickets. Kerberos avoids transmitting passwords over the network. Kerberoasting attacks target service account hashes.' },
  { id: 'fc186', domainId: 4, front: 'RBAC (Role-Based Access Control)', back: 'Access permissions are assigned to roles (e.g., "HR Manager," "Network Admin"), and users are assigned to roles rather than receiving individual permissions. RBAC simplifies administration and enforces least privilege. Role assignments must be reviewed regularly to prevent privilege creep.' },
  { id: 'fc187', domainId: 4, front: 'ABAC (Attribute-Based Access Control)', back: 'Access decisions are based on attributes of the user (department, clearance level), resource (classification, owner), and environment (time of day, location). ABAC is more granular and dynamic than RBAC and is well-suited for complex, context-aware access control policies. It is more complex to implement and manage.' },
  { id: 'fc188', domainId: 4, front: 'MAC (Mandatory Access Control)', back: 'Access is controlled by the operating system based on security labels assigned to subjects and objects. Users cannot override these policies. Used in high-security government environments (SELinux, AppArmor). Labels typically represent classification levels: Unclassified, Confidential, Secret, Top Secret.' },
  { id: 'fc189', domainId: 4, front: 'DAC (Discretionary Access Control)', back: 'Resource owners control access to their own resources and can grant or deny access to other users at their discretion. DAC is flexible but difficult to manage at scale and prone to excessive permissions. Standard Unix file permissions (owner/group/other) are a classic DAC example.' },
  { id: 'fc190', domainId: 4, front: 'DLP (Data Loss Prevention)', back: 'A set of tools and processes that detect and prevent unauthorized transmission, copying, or storage of sensitive data. DLP can be deployed at the endpoint (agent-based), network (inline inspection), and cloud (CASB). DLP policies are defined by data classification — for example, blocking emails containing credit card numbers.' },
  { id: 'fc191', domainId: 4, front: 'SPF (Sender Policy Framework)', back: 'A DNS-based email authentication mechanism that specifies which mail servers are authorized to send email on behalf of a domain. Recipients check the sending server\'s IP against the domain\'s SPF DNS record. SPF alone does not protect against header-spoofing; it must be combined with DKIM and DMARC.' },
  { id: 'fc192', domainId: 4, front: 'DKIM (DomainKeys Identified Mail)', back: 'An email authentication method that adds a cryptographic signature to email headers, allowing recipients to verify the email was sent by an authorized server and was not altered in transit. DKIM uses public key cryptography — the public key is published in DNS. DKIM alone doesn\'t tell receivers what to do with failures.' },
  { id: 'fc193', domainId: 4, front: 'DMARC (Domain-based Message Authentication, Reporting, and Conformance)', back: 'Builds on SPF and DKIM to give domain owners a policy mechanism (none, quarantine, reject) for handling unauthenticated emails and a reporting mechanism to receive feedback from mail receivers. DMARC with a "reject" policy is the gold standard for preventing email spoofing and phishing impersonating your domain.' },
  { id: 'fc194', domainId: 4, front: 'Email Gateway / Secure Email Gateway (SEG)', back: 'A security solution that inspects inbound and outbound email for spam, phishing, malware, and data loss. SEGs apply anti-spam filtering, attachment sandboxing, URL rewriting, and DMARC enforcement. Cloud-based SEGs (e.g., Proofpoint, Mimecast) handle filtering before email reaches the mail server.' },
  { id: 'fc195', domainId: 4, front: 'Sandbox Analysis', back: 'Executing suspicious files or URLs in an isolated virtual environment to observe their behavior safely without risking production systems. Sandboxes detect malware that evades signature-based detection by analyzing actual runtime behavior — file system changes, network connections, registry modifications. Limitation: some malware detects sandboxes and behaves differently.' },
  { id: 'fc196', domainId: 4, front: 'Honeypot / Honeynet', back: 'A honeypot is a decoy system designed to attract and detect attackers, gathering intelligence on their techniques. A honeynet is a network of honeypots. Honeypots generate high-fidelity alerts because legitimate users have no reason to interact with them. They provide valuable threat intelligence and early warning of attackers inside the network.' },
  { id: 'fc197', domainId: 4, front: 'Security Orchestration', back: 'Connecting and coordinating disparate security tools so they work together — sharing data, triggering actions, and executing workflows automatically. Orchestration is a key function of SOAR platforms. For example, when an IDS fires, orchestration can automatically quarantine the host, gather enrichment data, and open a ticket.' },
  { id: 'fc198', domainId: 4, front: 'Playbook (IR)', back: 'A documented, step-by-step procedure for responding to a specific type of security incident (e.g., ransomware, phishing, data breach). Playbooks reduce response time, ensure consistency, and help less experienced analysts follow the correct process. SOAR platforms can automate playbook execution.' },
  { id: 'fc199', domainId: 4, front: 'Mean Time to Detect (MTTD)', back: 'The average time elapsed between when an attack begins and when it is detected by the security team. Reducing MTTD minimizes attacker dwell time and limits potential damage. Improving MTTD requires better detection tools, threat hunting, and optimized alerting and correlation rules in the SIEM.' },
  { id: 'fc200', domainId: 4, front: 'Mean Time to Respond (MTTR)', back: 'The average time taken to contain and remediate a security incident after detection. MTTR measures IR effectiveness. Automation (SOAR), well-tested playbooks, and trained IR teams reduce MTTR. Both MTTD and MTTR are key security operations metrics used to demonstrate program effectiveness.' },
  { id: 'fc201', domainId: 4, front: 'Network Traffic Analysis (NTA)', back: 'Monitoring and analyzing network traffic patterns to detect anomalies, lateral movement, data exfiltration, and command-and-control communication. NTA tools use NetFlow data, packet capture, and behavioral baselines. NDR (Network Detection and Response) is a modern term for advanced NTA with response capabilities.' },
  { id: 'fc202', domainId: 4, front: 'NetFlow', back: 'A network protocol developed by Cisco that collects metadata about IP traffic flows (source/destination IP and port, protocol, duration, bytes transferred) without capturing full packet payloads. NetFlow data is used for traffic analysis, capacity planning, and detecting anomalies like data exfiltration. IPFIX is the IETF standard version.' },
  { id: 'fc203', domainId: 4, front: 'Packet Capture (PCAP)', back: 'Recording the full contents of network packets for analysis. Tools: Wireshark, tcpdump. PCAPs provide complete visibility into network communications but require significant storage and raise privacy concerns. PCAPs are essential for forensic analysis of network-based attacks and malware C2 communication analysis.' },
  { id: 'fc204', domainId: 4, front: 'DNS Sinkholing', back: 'Redirecting DNS queries for malicious domains to a controlled sinkhole IP address instead of the actual C2 server. This neutralizes malware\'s ability to receive commands and identify infected hosts that are querying the malicious domain. Sinkholing is used by defenders and law enforcement to disrupt botnets.' },
  { id: 'fc205', domainId: 4, front: 'User and Entity Behavior Analytics (UEBA)', back: 'Uses machine learning to establish baselines of normal behavior for users and entities (devices, applications) and alerts on anomalous deviations. UEBA detects insider threats, compromised accounts, and stealthy attacks that evade rule-based detection. It is often integrated into SIEM platforms.' },
  { id: 'fc206', domainId: 4, front: 'Privileged Access Workstation (PAW)', back: 'A dedicated, hardened workstation used exclusively for administrative tasks. PAWs prevent administrators from performing high-privilege actions on devices also used for email, browsing, and general work — reducing the risk that a compromised workstation leads to administrative credential theft.' },
  { id: 'fc207', domainId: 4, front: 'Just-in-Time (JIT) Access', back: 'Providing privileged access only for a defined, limited time window when needed, then automatically revoking it. JIT access eliminates standing privileges that persist indefinitely and are attractive targets for attackers. It is a key feature of modern PAM solutions and reduces the window of opportunity for misuse.' },
  { id: 'fc208', domainId: 4, front: 'Separation of Duties (SoD)', back: 'Dividing critical tasks or permissions among multiple people so that no single person can complete a sensitive process alone. For example, requiring a second person to approve a wire transfer or code deployment. SoD is a key fraud prevention and insider threat mitigation control, especially in financial and regulated environments.' },
  { id: 'fc209', domainId: 4, front: 'Dual Control', back: 'Requiring two or more authorized individuals to be present simultaneously to perform a sensitive action. Dual control is stronger than separation of duties because collusion requires active participation of both parties at the same time. Common in banking (safe deposit boxes) and nuclear launch procedures.' },
  { id: 'fc210', domainId: 4, front: 'Account Lifecycle Management', back: 'The process of managing user accounts from creation through modification to deactivation/deletion. Key practices: immediate deprovisioning when employees leave (onboarding/offboarding), periodic access reviews, and ensuring orphaned accounts are removed. Automated provisioning tied to HR systems improves consistency and speed.' },
  { id: 'fc211', domainId: 4, front: 'Group Policy Object (GPO)', back: 'A Windows Active Directory feature that allows centralized configuration and enforcement of security settings across computers and users in a domain. GPOs can enforce password policies, software restrictions, drive encryption, firewall settings, and more. GPO misconfiguration is a common source of security weaknesses.' },
  { id: 'fc212', domainId: 4, front: 'Mobile Device Management (MDM)', back: 'Software that remotely manages, monitors, and secures mobile devices (smartphones, tablets). MDM can enforce device encryption, require passcodes, push configurations, remotely wipe lost/stolen devices, and restrict app installation. MDM is essential for BYOD programs and remote workforce security.' },
  { id: 'fc213', domainId: 4, front: 'BYOD (Bring Your Own Device)', back: 'A policy allowing employees to use personal devices for work purposes. BYOD increases productivity but introduces security risks: unmanaged devices, mixing personal/corporate data, difficulty enforcing security policies. Controls: MDM enrollment, containerization of work apps, network segmentation for personal devices.' },
  { id: 'fc214', domainId: 4, front: 'Containerization (Mobile)', back: 'On mobile devices, containerization creates a separate, encrypted workspace for corporate apps and data, isolated from personal use. If the device is lost or the employee leaves, only the container can be wiped without affecting personal data. Tools: VMware Workspace ONE, Microsoft Intune.' },
  { id: 'fc215', domainId: 4, front: 'Geofencing', back: 'Using GPS, Wi-Fi, cellular, or RFID to define a virtual geographic boundary and triggering actions when a device enters or leaves. In security, geofencing can restrict access (block logins from unexpected countries), trigger alerts, or initiate remote wipe when a device leaves an approved area.' },
  { id: 'fc216', domainId: 4, front: 'Removable Media Controls', back: 'Policies and technical controls restricting the use of USB drives, external hard drives, and other removable media to prevent data exfiltration and malware introduction. Controls: USB port disabling via GPO/MDM, DLP agents on endpoints, device allow-listing, and mandatory encryption for approved removable media.' },
  { id: 'fc217', domainId: 4, front: 'Secure Baseline / Hardening Guide', back: 'A documented set of security configuration settings that define the minimum secure state for a system type. CIS Benchmarks and DISA STIGs are widely used baseline sources. Baseline configurations should be applied to all new systems and validated regularly. Deviations require documented exceptions and compensating controls.' },
  { id: 'fc218', domainId: 4, front: 'Vulnerability Remediation Prioritization', back: 'The process of ranking vulnerabilities by risk to determine the order and urgency of patching. Factors: CVSS score, exploitability (is there a public exploit?), asset criticality, and exposure (internet-facing vs. internal). Known Exploited Vulnerabilities (KEV) catalog published by CISA identifies vulnerabilities actively exploited in the wild.' },
  { id: 'fc219', domainId: 4, front: 'Cyber Threat Intelligence (CTI) Feeds', back: 'Structured data about threats shared between organizations, ISACs (Information Sharing and Analysis Centers), and government agencies. Common formats: STIX (Structured Threat Information Expression) for the content, TAXII (Trusted Automated eXchange of Indicator Information) for the transport. CTI feeds populate SIEM rules and block lists.' },
  { id: 'fc220', domainId: 4, front: 'False Positive vs. False Negative (security)', back: 'A false positive is an alert for a benign event incorrectly flagged as malicious — wastes analyst time. A false negative is a genuine attack that was not detected — far more dangerous. Security tuning seeks to minimize both. High false-positive rates lead to alert fatigue, causing analysts to miss genuine incidents.' },
  { id: 'fc221', domainId: 4, front: 'Alert Fatigue', back: 'The desensitization of security analysts caused by an overwhelming volume of security alerts, many of which are false positives. Alert fatigue leads analysts to ignore or dismiss alerts, increasing the risk of missing real incidents. Mitigations: tuning detection rules, using SOAR automation, and tiered analyst workflows.' },
  { id: 'fc222', domainId: 4, front: 'Tabletop Exercise', back: 'A discussion-based IR exercise where participants talk through a simulated scenario to identify gaps in plans, processes, and communication without deploying actual resources. Tabletops test the IR plan and decision-making of key stakeholders (legal, HR, PR, IT, executive). They are low-cost, high-value preparation activities.' },
  { id: 'fc223', domainId: 4, front: 'Wireless Security Protocols: WPA2 vs. WPA3', back: 'WPA2 uses AES-CCMP encryption and is vulnerable to offline dictionary attacks against the 4-way handshake. WPA3 introduces SAE (Simultaneous Authentication of Equals), which provides forward secrecy and resists offline attacks. WPA3 is the current standard; WPA3-Enterprise requires 192-bit cryptography.' },
  { id: 'fc224', domainId: 4, front: 'SSID Hiding', back: 'Configuring a wireless access point to not broadcast its SSID (network name) in beacon frames. This is security through obscurity — not a true security control, as passive sniffers can still detect the network during client association. Strong authentication (WPA3, 802.1X) provides real protection.' },
  { id: 'fc225', domainId: 4, front: 'MAC Address Filtering', back: 'Restricting wireless network access to devices with pre-approved MAC addresses. MAC filtering provides minimal security because MAC addresses are transmitted in plaintext and can be spoofed in seconds with freely available tools. It should be used only as a complementary measure, not a primary control.' },
  { id: 'fc226', domainId: 4, front: 'Physical Security Controls', back: 'Controls that protect physical access to facilities and hardware. Examples: security guards, badge readers, biometric scanners, mantraps, CCTV cameras, cable locks, and server cage locks. Physical security is the foundation of all other security — an attacker with physical access can often bypass all technical controls.' },
  { id: 'fc227', domainId: 4, front: 'CCTV / Video Surveillance', back: 'Closed-circuit television systems used to monitor facilities for unauthorized access, security incidents, and policy violations. CCTV footage provides evidence for forensic investigations. Modern IP-based camera systems require their own security hardening — many IoT cameras have had critical vulnerabilities exploited in the wild.' },
  { id: 'fc228', domainId: 4, front: 'Mantrap (Security Vestibule)', back: 'A physical access control mechanism using two interlocking doors where the first door must close before the second can open, allowing only one person at a time. Mantraps prevent tailgating and piggybacking. They are used in high-security areas such as data centers, vaults, and secure government facilities.' },
  { id: 'fc229', domainId: 4, front: 'Data Sanitization Methods', back: 'The secure removal of data from storage media before disposal or reuse. Methods: overwriting (writing patterns over all sectors), degaussing (strong magnetic field to erase magnetic media), cryptographic erasure (destroying encryption keys so encrypted data is unreadable), and physical destruction (shredding, crushing). Method choice depends on media type and data sensitivity.' },
  { id: 'fc230', domainId: 4, front: 'Secure Coding Practices', back: 'Development practices that reduce vulnerabilities in software. Key practices: input validation, output encoding, parameterized queries, avoiding hardcoded credentials, error handling without information disclosure, using vetted libraries, and conducting code reviews. Following OWASP secure coding guidelines is a recognized industry standard.' },
  { id: 'fc231', domainId: 4, front: 'Code Signing', back: 'Digitally signing software executables and scripts with a trusted certificate to prove authenticity (the code comes from a known publisher) and integrity (the code has not been tampered with). Operating systems can be configured to reject unsigned code. Code signing is a key defense against supply chain attacks and malware masquerading as legitimate software.' },
  { id: 'fc232', domainId: 4, front: 'Secure DevOps / DevSecOps', back: 'Integrating security practices into the DevOps pipeline so that security is automated and continuous rather than a gate at the end. Practices: SAST in CI pipeline, dependency scanning (SCA), container image scanning, IaC security analysis, secrets detection in code, and automated compliance checks. Promotes a "security as code" mindset.' },
  { id: 'fc233', domainId: 4, front: 'Secrets Management', back: 'Securely storing, distributing, and rotating sensitive credentials such as API keys, passwords, tokens, and certificates used by applications and automation. Tools: HashiCorp Vault, AWS Secrets Manager, Azure Key Vault. Secrets must never be hardcoded in source code, configuration files, or environment variables in production.' },
  { id: 'fc234', domainId: 4, front: 'Network Segmentation', back: 'Dividing a network into isolated segments using firewalls, VLANs, and routing policies to limit lateral movement and contain breaches. Each segment should be sized to the principle of least communication — segments should only be able to communicate with other segments they functionally need to reach.' },
  { id: 'fc235', domainId: 4, front: 'Egress Filtering', back: 'Controlling outbound network traffic from internal systems, typically to prevent data exfiltration and block malware from communicating with C2 servers. Egress filtering blocks unauthorized outbound ports, restricts DNS to approved resolvers, and inspects outbound web traffic through a proxy. Often neglected compared to ingress filtering.' },
  { id: 'fc236', domainId: 4, front: 'Intrusion Detection: Network-Based (NIDS) vs. Host-Based (HIDS)', back: 'A NIDS monitors network traffic across a segment for attack signatures and anomalies. A HIDS is installed on individual endpoints and monitors system calls, file integrity, logs, and process activity. NIDS provides broad network visibility; HIDS provides deep endpoint visibility. Both are complementary.' },
  { id: 'fc237', domainId: 4, front: 'File Integrity Monitoring (FIM)', back: 'Continuously monitors critical system files, configuration files, and executables for unauthorized changes using cryptographic hashing. If a monitored file is modified — even by malware — an alert is generated. FIM is required by PCI-DSS and is a key HIDS capability. Tools: Tripwire, OSSEC, Wazuh.' },
  { id: 'fc238', domainId: 4, front: 'Forensic Image', back: 'A bit-for-bit copy of a storage device captured using forensic tools that preserve all data, including deleted files, slack space, and metadata. The forensic image is hashed (MD5/SHA-256) at acquisition and periodically thereafter to prove it has not been altered. Analysis is performed on the image, not the original device.' },
  { id: 'fc239', domainId: 4, front: 'Memory Forensics', back: 'Capturing and analyzing the contents of RAM to recover evidence that would be lost when the system is powered off — such as running processes, encryption keys, network connections, and injected malware. Tools: Volatility, Rekall. Memory forensics is critical for analyzing fileless malware and rootkits.' },
  { id: 'fc240', domainId: 4, front: 'IOC Enrichment', back: 'Adding context to raw indicator of compromise data — such as associating an IP address with a known threat actor, geolocation, or past attack campaigns — using threat intelligence platforms. Enriched IoCs help analysts prioritize response and understand the broader attack context. Platforms: VirusTotal, MISP, ThreatConnect.' },

  // ─── Domain 5: Security Program Management & Oversight (~60 cards) ─────────

  { id: 'fc241', domainId: 5, front: 'Risk Management', back: 'The process of identifying, assessing, and mitigating risks to an acceptable level. Risk management is continuous, not a one-time activity. The four responses to risk are: accept, avoid, transfer (insurance), and mitigate (apply controls). The chosen response depends on risk appetite and the cost-benefit analysis of controls.' },
  { id: 'fc242', domainId: 5, front: 'Risk Appetite vs. Risk Tolerance', back: 'Risk appetite is the broad level of risk an organization is willing to accept in pursuit of its objectives — a strategic, qualitative statement. Risk tolerance is the acceptable variation in outcomes related to a specific risk — a more precise, often quantitative boundary. Both are defined by leadership and the board.' },
  { id: 'fc243', domainId: 5, front: 'Qualitative Risk Assessment', back: 'Risk is assessed using subjective categories (high/medium/low) based on judgment and expert opinion rather than numerical data. It is faster and less data-intensive than quantitative methods. Common output: risk matrix (likelihood × impact). Useful when precise financial data is unavailable or impractical to gather.' },
  { id: 'fc244', domainId: 5, front: 'Quantitative Risk Assessment', back: 'Risk is expressed in financial terms using formulas. Key values: Asset Value (AV), Exposure Factor (EF), Single Loss Expectancy (SLE = AV × EF), Annual Rate of Occurrence (ARO), Annual Loss Expectancy (ALE = SLE × ARO). Quantitative assessment enables cost-benefit analysis of security controls.' },
  { id: 'fc245', domainId: 5, front: 'SLE (Single Loss Expectancy)', back: 'The expected financial loss from a single occurrence of a risk event. SLE = Asset Value (AV) × Exposure Factor (EF). For example, if a server worth $100,000 has an EF of 40% (40% of value lost per incident), SLE = $40,000. SLE is a building block for calculating Annual Loss Expectancy (ALE).' },
  { id: 'fc246', domainId: 5, front: 'ALE (Annual Loss Expectancy)', back: 'The expected annual financial loss from a specific risk. ALE = SLE × ARO. If SLE = $40,000 and the threat occurs twice per year (ARO = 2), ALE = $80,000. The cost of a security control should not exceed the reduction in ALE it provides (cost-benefit analysis).' },
  { id: 'fc247', domainId: 5, front: 'BCP (Business Continuity Plan)', back: 'A comprehensive plan that ensures critical business functions can continue during and after a disaster or major disruption. BCP encompasses people, processes, technology, and facilities. It is broader than a DR plan — BCP focuses on keeping the business operational; DR focuses on recovering IT systems.' },
  { id: 'fc248', domainId: 5, front: 'DRP (Disaster Recovery Plan)', back: 'The subset of BCP focused specifically on restoring IT systems and data after a disaster. A DRP defines which systems are restored first, in what order, and by whom. It includes procedures for restoring from backups, switching to DR sites, and testing recovery. Key metrics: RTO and RPO.' },
  { id: 'fc249', domainId: 5, front: 'RTO (Recovery Time Objective)', back: 'The maximum acceptable time for a system or process to be offline after a disruption before unacceptable business impact occurs. A lower RTO requires more investment in HA and DR infrastructure. RTO drives decisions about hot vs. warm vs. cold standby systems.' },
  { id: 'fc250', domainId: 5, front: 'RPO (Recovery Point Objective)', back: 'The maximum acceptable amount of data loss measured in time — how far back in time can the organization afford to recover data from? An RPO of 4 hours means backups must be taken at least every 4 hours. Lower RPO requires more frequent backups or continuous replication.' },
  { id: 'fc251', domainId: 5, front: 'Hot Site', back: 'A fully equipped, fully staffed DR facility that is a near-mirror of the primary site and can take over operations within minutes to hours. Hot sites are the most expensive DR option but provide the lowest RTO. Data replication is continuous or near-real-time.' },
  { id: 'fc252', domainId: 5, front: 'Warm Site', back: 'A DR facility with hardware and connectivity in place but without the most current data — the environment is set up but must have recent data restored before operations can resume. Recovery takes hours to days. Warm sites are a cost-effective middle ground between hot and cold sites.' },
  { id: 'fc253', domainId: 5, front: 'Cold Site', back: 'A DR facility with only basic infrastructure (power, cooling, network connectivity) and no pre-configured hardware or data. Organizations must ship in equipment and restore data from backup before operations can resume — typically takes days to weeks. Cold sites are the least expensive but have the highest RTO.' },
  { id: 'fc254', domainId: 5, front: 'BIA (Business Impact Analysis)', back: 'A process that identifies critical business functions and quantifies the impact of their disruption over time. BIA determines which functions are most critical, establishes RTO and RPO requirements for each, and identifies internal and external dependencies. BIA findings drive BCP/DRP priorities and resource allocation.' },
  { id: 'fc255', domainId: 5, front: 'HIPAA (Health Insurance Portability and Accountability Act)', back: 'A U.S. federal law protecting the privacy and security of Protected Health Information (PHI). The Security Rule requires covered entities and business associates to implement administrative, physical, and technical safeguards. Violations can result in civil and criminal penalties. A risk analysis is explicitly required.' },
  { id: 'fc256', domainId: 5, front: 'PCI-DSS (Payment Card Industry Data Security Standard)', back: 'A set of security requirements for organizations that store, process, or transmit cardholder data. PCI-DSS has 12 main requirements covering network security, access control, encryption, monitoring, and testing. Compliance is assessed by Qualified Security Assessors (QSAs) or self-assessment questionnaires (SAQs).' },
  { id: 'fc257', domainId: 5, front: 'GDPR (General Data Protection Regulation)', back: 'A European Union regulation protecting the personal data of EU residents, regardless of where the processing organization is located. Key requirements: lawful basis for processing, data subject rights (access, erasure, portability), privacy by design, mandatory breach notification within 72 hours, and Data Protection Officers (DPOs) for some organizations.' },
  { id: 'fc258', domainId: 5, front: 'FISMA (Federal Information Security Modernization Act)', back: 'A U.S. federal law requiring federal agencies to develop, document, and implement information security programs. FISMA mandates use of NIST frameworks (SP 800-53, RMF). Agencies must receive an Authority to Operate (ATO) before deploying systems. The OMB and DHS oversee FISMA compliance.' },
  { id: 'fc259', domainId: 5, front: 'CMMC (Cybersecurity Maturity Model Certification)', back: 'A U.S. Department of Defense framework requiring defense contractors to demonstrate cybersecurity maturity at one of three levels to win DoD contracts. CMMC Level 1 covers basic cyber hygiene (17 practices); Level 2 aligns with NIST SP 800-171 (110 practices); Level 3 adds additional advanced requirements.' },
  { id: 'fc260', domainId: 5, front: 'SOC 2 (Service Organization Control 2)', back: 'An auditing standard developed by the AICPA for service organizations, assessing controls related to five Trust Service Criteria: Security, Availability, Processing Integrity, Confidentiality, and Privacy. SOC 2 Type I assesses controls at a point in time; Type II assesses operational effectiveness over a period (typically 6-12 months).' },
  { id: 'fc261', domainId: 5, front: 'Data Classification', back: 'The process of categorizing data based on sensitivity and required protection level. Government classification: Unclassified, Controlled Unclassified Information (CUI), Confidential, Secret, Top Secret. Commercial classification: Public, Internal, Confidential, Restricted/Highly Confidential. Classification drives appropriate security controls and handling requirements.' },
  { id: 'fc262', domainId: 5, front: 'Data Retention Policy', back: 'Defines how long different types of data must be kept and when it should be securely destroyed. Retention periods are driven by legal and regulatory requirements (e.g., financial records 7 years, HIPAA records 6 years). Retaining data longer than required increases breach exposure and e-discovery costs.' },
  { id: 'fc263', domainId: 5, front: 'Data Sovereignty', back: 'The concept that data is subject to the laws and governance of the country in which it is stored or processed. Organizations using cloud services must ensure sensitive data is stored in compliant jurisdictions. EU GDPR, for example, restricts transfer of personal data to countries without adequate data protection laws.' },
  { id: 'fc264', domainId: 5, front: 'Privacy by Design', back: 'A framework (foundational to GDPR) that requires privacy to be built into systems and processes from the outset, not added as an afterthought. Seven principles include: proactive not reactive, privacy as the default setting, end-to-end security, full functionality (not privacy vs. security), and visibility and transparency.' },
  { id: 'fc265', domainId: 5, front: 'Vendor Risk Management (Third-Party Risk)', back: 'The process of identifying, assessing, and mitigating security risks introduced by third-party vendors, suppliers, and partners who have access to an organization\'s data or systems. Key activities: security questionnaires, SOC 2 reviews, right-to-audit clauses, contractual security requirements, and ongoing monitoring.' },
  { id: 'fc266', domainId: 5, front: 'SLA (Service Level Agreement)', back: 'A contractual commitment between a service provider and customer defining the expected level of service — including availability, performance, security obligations, and breach notification timelines. SLAs for cloud and managed security services should specify security controls, incident response requirements, and penalties for non-compliance.' },
  { id: 'fc267', domainId: 5, front: 'MSSP (Managed Security Service Provider)', back: 'A third-party provider that manages an organization\'s security operations — typically including 24/7 SOC monitoring, SIEM management, threat intelligence, and incident response. MSSPs allow organizations to access security expertise without building a full in-house security team. Due diligence and clear SLAs are essential when engaging an MSSP.' },
  { id: 'fc268', domainId: 5, front: 'Security Awareness Training', back: 'Educating employees about security risks, policies, and safe behaviors. Effective programs use varied formats (videos, interactive modules, newsletters), cover relevant topics (phishing, password hygiene, social engineering, data handling), and are repeated regularly. Training is required by regulations including HIPAA, PCI-DSS, and CMMC.' },
  { id: 'fc269', domainId: 5, front: 'Phishing Simulation', back: 'Sending controlled, fake phishing emails to employees to measure susceptibility and identify who needs additional training. Employees who click are provided immediate, contextual training. Phishing simulations should be realistic and followed by supportive coaching rather than punitive action. Metrics: click rate, report rate, training completion.' },
  { id: 'fc270', domainId: 5, front: 'Red Team', back: 'An adversarial group that simulates realistic attacks against an organization\'s people, processes, and technology to identify exploitable weaknesses. Red teams use the same tactics, techniques, and procedures (TTPs) as real threat actors, including social engineering and physical attacks. They report findings to improve defenses.' },
  { id: 'fc271', domainId: 5, front: 'Blue Team', back: 'The internal security team responsible for defending the organization — operating the SOC, managing security tools, responding to incidents, and hardening systems. Blue teams defend against red team attacks and real threats. After red team exercises, the blue team reviews what was missed to improve detection and response.' },
  { id: 'fc272', domainId: 5, front: 'Purple Team', back: 'A collaborative approach where red and blue teams work together simultaneously — the red team attacks while the blue team tries to detect and respond in real time, with both teams sharing knowledge. Purple teaming accelerates the improvement of detection and response capabilities more efficiently than separate red/blue exercises.' },
  { id: 'fc273', domainId: 5, front: 'Penetration Testing Types: External vs. Internal', back: 'External pen testing targets internet-facing systems to simulate an outside attacker with no prior access. Internal pen testing simulates an insider or attacker who has already gained a foothold — testing lateral movement, privilege escalation, and access to sensitive internal data. Both types provide different, valuable perspectives.' },
  { id: 'fc274', domainId: 5, front: 'Rules of Engagement (Pen Test)', back: 'A formal agreement between the pen test client and the testing team that defines the scope, boundaries, timeframes, permitted techniques, out-of-scope systems, communication protocols, and emergency contacts. Rules of engagement protect both parties legally and ensure testing does not cause unintended disruption.' },
  { id: 'fc275', domainId: 5, front: 'Bug Bounty Program', back: 'A program that incentivizes external security researchers to find and responsibly disclose vulnerabilities in an organization\'s systems in exchange for financial rewards or recognition. Bug bounties extend the organization\'s testing resources by leveraging a global pool of security talent. Clear scope and disclosure policies are essential.' },
  { id: 'fc276', domainId: 5, front: 'Responsible Disclosure / Coordinated Vulnerability Disclosure', back: 'A process where a security researcher privately reports a vulnerability to the affected vendor, giving them time to develop and release a patch before public disclosure. Coordinated disclosure allows vendors to fix issues before exploitation while giving researchers credit. Full disclosure (immediate public release) is a more aggressive alternative.' },
  { id: 'fc277', domainId: 5, front: 'Security Policy', back: 'A high-level document approved by leadership that defines an organization\'s security objectives, principles, and responsibilities. Policies are mandatory and must be followed by all employees. They are supported by standards (specific requirements), guidelines (recommendations), and procedures (step-by-step instructions).' },
  { id: 'fc278', domainId: 5, front: 'Acceptable Use Policy (AUP)', back: 'A policy that defines the permitted and prohibited uses of organizational IT resources (internet, email, devices, systems). AUPs protect the organization legally and set clear expectations for employees. AUPs typically prohibit activities like accessing inappropriate content, using systems for personal gain, or sharing credentials.' },
  { id: 'fc279', domainId: 5, front: 'Information Security Policy Hierarchy', back: 'Policy (why and what — high level, board-approved) → Standard (specific, mandatory requirements — e.g., "passwords must be 12+ characters") → Guideline (recommended, not mandatory — "consider using a password manager") → Procedure (step-by-step instructions — "here is how to reset a password"). Understanding the hierarchy is important for the exam.' },
  { id: 'fc280', domainId: 5, front: 'Governance, Risk, and Compliance (GRC)', back: 'A framework that aligns IT governance (decision-making and accountability), risk management (identifying and mitigating risks), and compliance (meeting regulatory and contractual obligations) into an integrated program. GRC tools centralize policy management, risk registers, control testing, and audit evidence. Strong GRC reduces organizational risk.' },
  { id: 'fc281', domainId: 5, front: 'Security Audit', back: 'A formal, systematic examination of an organization\'s security controls, policies, and procedures to assess their effectiveness and compliance with standards or regulations. Audits may be internal (self-assessment) or external (third-party). Audit findings drive remediation activities. Evidence collected during audits must be managed carefully.' },
  { id: 'fc282', domainId: 5, front: 'Audit Log', back: 'A chronological record of events and activities that provides evidence of who did what, when, and from where. Audit logs are essential for forensic investigations, compliance (HIPAA, PCI-DSS require specific log types), and accountability. Logs must be protected from tampering — write-once media or SIEM with integrity checking.' },
  { id: 'fc283', domainId: 5, front: 'Risk Register', back: 'A document or tool that records identified risks, their likelihood and impact assessments, assigned owners, current mitigation status, and residual risk. The risk register is the central artifact of an organization\'s risk management program and is reviewed regularly by leadership. It ensures risks are tracked and not forgotten.' },
  { id: 'fc284', domainId: 5, front: 'Residual Risk', back: 'The risk that remains after security controls have been applied. No control eliminates risk entirely. Residual risk must be accepted by management or reduced further. The difference between inherent risk (risk without controls) and residual risk reflects the effectiveness of implemented controls.' },
  { id: 'fc285', domainId: 5, front: 'Risk Transfer', back: 'Shifting the financial consequence of a risk to a third party, typically through cyber insurance or outsourcing. Cyber insurance policies cover breach costs, ransomware payments, legal liability, and notification costs. Risk transfer does not eliminate the risk — it only addresses the financial impact. Insurers increasingly require demonstrated security controls.' },
  { id: 'fc286', domainId: 5, front: 'Cyber Insurance', back: 'An insurance product covering financial losses from cyber incidents: breach response costs, legal fees, regulatory fines, ransomware payments, and business interruption. Insurers conduct security assessments before underwriting and may require specific controls (MFA, EDR, backups). Cyber insurance is a form of risk transfer.' },
  { id: 'fc287', domainId: 5, front: 'Security Metrics and KPIs', back: 'Quantifiable measures used to evaluate the effectiveness of a security program. Examples: MTTD, MTTR, patch coverage percentage, phishing click rate, number of critical vulnerabilities unpatched after SLA. KPIs should be aligned with business objectives and reported to leadership regularly to demonstrate program value.' },
  { id: 'fc288', domainId: 5, front: 'Data Privacy Officer (DPO)', back: 'A role mandated by GDPR for organizations that process personal data at large scale, process special categories of data, or conduct large-scale monitoring of individuals. The DPO is responsible for ensuring GDPR compliance, advising on data protection impact assessments (DPIAs), and serving as the contact point for supervisory authorities.' },
  { id: 'fc289', domainId: 5, front: 'Privacy Impact Assessment (PIA) / DPIA', back: 'A process that evaluates how a new project, system, or process will collect, use, store, and share personal data and identifies privacy risks. GDPR requires a Data Protection Impact Assessment (DPIA) for high-risk processing activities. PIAs/DPIAs should be conducted before implementing new systems that handle personal data.' },
  { id: 'fc290', domainId: 5, front: 'NIST Risk Management Framework (RMF)', back: 'A seven-step framework for managing security and privacy risk in federal information systems: Prepare → Categorize → Select → Implement → Assess → Authorize → Monitor. The RMF integrates with FISMA and maps to NIST SP 800-53 security controls. The Authorize step produces an Authority to Operate (ATO) decision.' },
  { id: 'fc291', domainId: 5, front: 'Authority to Operate (ATO)', back: 'A formal authorization granted by a designated authority (Authorizing Official) confirming that a federal information system has been assessed and its residual risk is acceptable for operation. ATOs are required under FISMA and the NIST RMF. ATOs have a defined timeframe (typically 3 years) and require continuous monitoring.' },
  { id: 'fc292', domainId: 5, front: 'Security Control Assessment', back: 'An independent evaluation that examines whether security controls are implemented correctly, operating as intended, and producing the desired security outcome. Assessors use testing, interviewing, and examination of documentation. Results inform the authorization decision (ATO) and the plan of action and milestones (POA&M).' },
  { id: 'fc293', domainId: 5, front: 'POA&M (Plan of Action and Milestones)', back: 'A document that identifies weaknesses found in a security assessment, assigns responsibility for remediation, and establishes target completion dates. POA&Ms are required under FISMA and are reviewed by auditors and authorizing officials to track progress toward risk reduction.' },
  { id: 'fc294', domainId: 5, front: 'Continuous Monitoring', back: 'Ongoing assessment of security controls to maintain situational awareness of an organization\'s security posture. Replaces point-in-time compliance snapshots with real-time or near-real-time monitoring using automated tools. Required by NIST RMF and increasingly by regulatory frameworks. SIEM, vulnerability scanners, and configuration management tools support continuous monitoring.' },
  { id: 'fc295', domainId: 5, front: 'Background Check / Personnel Security', back: 'Pre-employment screening to verify an applicant\'s identity, qualifications, criminal history, and trustworthiness before granting access to sensitive roles or systems. Ongoing personnel security includes periodic re-investigations for high-trust roles and monitoring for behavioral indicators of insider threat. Required by many regulations and government contracts.' },
  { id: 'fc296', domainId: 5, front: 'Separation of Duties (Policy)', back: 'A policy control requiring that no single individual has end-to-end control over a sensitive process — for example, no one person should be able to both approve and execute a financial transaction or request and fulfill their own access. SoD is enforced through role design and technical access controls, and verified through audits.' },
  { id: 'fc297', domainId: 5, front: 'Job Rotation', back: 'Periodically rotating employees through different roles. Job rotation reduces fraud risk by eliminating long-term collusion, helps detect irregularities when new people review past work, and cross-trains staff for resilience. It is particularly important for high-privilege roles such as system administrators and financial approvers.' },
  { id: 'fc298', domainId: 5, front: 'Mandatory Vacation', back: 'Requiring employees (particularly those in sensitive roles) to take a continuous block of uninterrupted vacation, during which their duties are performed by others. Mandatory vacation can reveal fraud or irregularities that the employee was concealing through active management of records. It is a detective control.' },
  { id: 'fc299', domainId: 5, front: 'Non-Disclosure Agreement (NDA)', back: 'A legal contract that obligates parties to maintain the confidentiality of specified information. NDAs are signed at hire, before sharing sensitive technical information with vendors, and sometimes at termination. NDAs are a legal (administrative) control that deters disclosure but do not prevent it technically.' },
  { id: 'fc300', domainId: 5, front: 'Security Awareness Culture', back: 'An organizational culture where every employee understands their role in protecting information assets and actively participates in security. Building a security culture requires consistent communication from leadership, relevant and engaging training, positive reinforcement of secure behaviors, and treating security as everyone\'s responsibility rather than only IT\'s.' },

  // ─── Domain 3 Expansion: Security Architecture (D3-001 through D3-065) ──────

  { id: 'D3-001', domainId: 3, front: 'What is network segmentation and why does it matter?', back: 'Network segmentation divides a network into isolated zones so that a compromise in one zone cannot freely spread to others. It limits lateral movement, reduces blast radius, and allows security policies to be applied per zone. Without segmentation, an attacker who compromises one workstation can often reach every other system on the network.' },
  { id: 'D3-002', domainId: 3, front: 'VLAN trunking — what is it and why is it a security concern?', back: 'Trunking carries multiple VLANs over a single physical link using 802.1Q tagging. VLAN hopping is a common attack: a misconfigured trunk port allows an attacker on one VLAN to inject tagged frames and reach other VLANs. Mitigations include setting all unused ports to access mode, disabling DTP, and assigning unused ports to a dedicated "black hole" VLAN.' },
  { id: 'D3-003', domainId: 3, front: 'Jump server / bastion host — definition and purpose', back: 'A hardened, single-purpose server that acts as the only entry point into a sensitive network segment (such as a DMZ or OT network). Administrators connect to the bastion host first and then pivot to internal resources. This funnels all administrative traffic through one auditable chokepoint, reducing attack surface and enabling detailed session logging.' },
  { id: 'D3-004', domainId: 3, front: 'Screened subnet vs. traditional DMZ', back: 'A DMZ uses one or two firewalls to create a semi-trusted zone between the internet and the internal network. A screened subnet is the same concept — the terms are often used interchangeably on the CompTIA exam. The key idea is that public-facing servers sit in the middle zone; breaching them still leaves the internal network protected by a second firewall.' },
  { id: 'D3-005', domainId: 3, front: 'East-west vs. north-south traffic in network security', back: 'North-south traffic flows between the internal network and external networks (internet). East-west traffic flows laterally between systems within the same network or data center. Traditional perimeter firewalls focus on north-south. In modern architectures, east-west traffic represents the greater threat because attackers who gain a foothold move laterally. Microsegmentation addresses east-west threats.' },
  { id: 'D3-006', domainId: 3, front: 'Microsegmentation — definition and relationship to Zero Trust', back: 'Microsegmentation enforces granular, workload-level network policies so that each application or server can only communicate with explicitly authorized peers. It directly implements the Zero Trust principle of "never trust, always verify" at the network layer. Even if an attacker compromises one workload, they cannot reach adjacent workloads without passing through a policy enforcement point.' },
  { id: 'D3-007', domainId: 3, front: 'Software-Defined Networking (SDN) — what it is', back: 'SDN separates the control plane (routing/forwarding decisions) from the data plane (actual packet forwarding) and centralizes control in a software controller. Network administrators program the controller instead of configuring individual devices. SDN enables rapid, consistent policy deployment across the entire network and makes microsegmentation much easier to implement at scale.' },
  { id: 'D3-008', domainId: 3, front: 'Forward proxy vs. reverse proxy — security roles', back: 'A forward proxy sits between internal clients and the internet, controlling and logging outbound traffic — used for content filtering, SSL inspection, and anonymous browsing. A reverse proxy sits in front of internal servers, accepting inbound requests on their behalf — used for load balancing, SSL termination, and WAF functionality. Understanding the direction matters on the exam.' },
  { id: 'D3-009', domainId: 3, front: 'Split tunneling in VPNs — what it is and its risk', back: 'Split tunneling allows a VPN user to send only traffic destined for corporate resources through the encrypted tunnel while other traffic (internet browsing) goes directly out the local connection. This reduces VPN load and improves performance but creates a security risk: the local connection bypasses corporate security controls, allowing malware on the endpoint to exfiltrate data or receive commands without going through the VPN.' },
  { id: 'D3-010', domainId: 3, front: 'Site-to-site VPN vs. remote-access VPN', back: 'A site-to-site VPN connects two entire networks (e.g., HQ and branch office) using gateway devices at each end — users are unaware of the VPN. A remote-access VPN connects an individual user\'s device to a corporate network, requiring VPN client software. Site-to-site uses IPSec; remote access commonly uses SSL/TLS or IPSec. CompTIA tests whether you can match the use case to the VPN type.' },
  { id: 'D3-011', domainId: 3, front: 'IPSec vs. SSL VPN — key differences', back: 'IPSec VPNs operate at Layer 3, encrypting all IP traffic between peers and are typically used for site-to-site connections. SSL/TLS VPNs operate at the application layer and are accessed via a web browser or thin client, making them easier to deploy for remote access. SSL VPNs often provide clientless access but are limited to application-level traffic; IPSec VPNs are more comprehensive.' },
  { id: 'D3-012', domainId: 3, front: 'SD-WAN security considerations', back: 'SD-WAN connects branch offices over any available transport (broadband, LTE, MPLS) using software intelligence. Security considerations include: traffic traverses untrusted internet links and must be encrypted, centralized SD-WAN controllers are a high-value attack target, and consistent security policy must be enforced across all links. Many organizations add a cloud security layer (SASE) on top of SD-WAN.' },
  { id: 'D3-013', domainId: 3, front: 'Community cloud deployment model', back: 'A cloud infrastructure shared among several organizations with common concerns — such as the same regulatory requirements, industry, or mission (e.g., government agencies sharing a FedRAMP-authorized cloud). It provides more control than public cloud but shares costs among members. Community clouds are less common than public, private, or hybrid models.' },
  { id: 'D3-014', domainId: 3, front: 'Cloud Security Posture Management (CSPM)', back: 'CSPM tools continuously monitor cloud environments for misconfigurations, compliance violations, and security risks — such as publicly exposed S3 buckets, overly permissive IAM roles, and unencrypted storage. CSPM provides visibility across multi-cloud environments and helps enforce security guardrails. It is a key control for organizations using IaaS and PaaS.' },
  { id: 'D3-015', domainId: 3, front: 'Cloud storage security risks and controls', back: 'Key risks include publicly accessible storage buckets (a leading cause of data breaches), overly permissive access policies, and lack of encryption. Controls: enable server-side encryption, apply bucket/container ACLs following least privilege, enable public access block settings, use CSPM to continuously audit configurations, and log all access. CompTIA frequently tests the public bucket misconfiguration scenario.' },
  { id: 'D3-016', domainId: 3, front: 'Container security best practices', back: 'Containers share the host OS kernel, so a vulnerability in one container can potentially affect the host. Key security practices: use minimal base images and scan them for vulnerabilities before deployment, run containers as non-root users, use read-only filesystems where possible, apply Kubernetes network policies to control pod-to-pod communication, and avoid privileged container mode.' },
  { id: 'D3-017', domainId: 3, front: 'Infrastructure as Code (IaC) security risks', back: 'IaC templates (Terraform, CloudFormation, ARM) define cloud infrastructure in code. Security risks: misconfigurations in templates (open security groups, public storage) propagate to production at scale, secrets and credentials may be embedded in template files, and unauthorized template changes can create backdoors. Mitigations include static analysis scanning (tfsec, Checkov), code review, and storing IaC in secured version control.' },
  { id: 'D3-018', domainId: 3, front: 'Serverless security considerations', back: 'Serverless (FaaS) functions execute in response to events and are managed by the cloud provider. Security concerns unique to serverless: overly permissive IAM roles granted to functions, insecure third-party dependencies injected at runtime, inadequate logging (functions may run for milliseconds — capturing all activity is critical), and event injection attacks where malicious input triggers unintended behavior.' },
  { id: 'D3-019', domainId: 3, front: 'AES block size, key sizes, and modes', back: 'AES uses 128-bit blocks regardless of key size. Key sizes are 128, 192, or 256 bits — longer keys provide more security but are slightly slower. Common modes: CBC (Cipher Block Chaining) — each block XORed with previous ciphertext, widely used but vulnerable to padding oracle attacks; GCM (Galois/Counter Mode) — provides both encryption and authentication (AEAD), required in TLS 1.3; CTR (Counter Mode) — turns AES into a stream cipher. GCM is the preferred mode.' },
  { id: 'D3-020', domainId: 3, front: 'Why is 1024-bit RSA deprecated?', back: 'RSA security relies on the difficulty of factoring large prime numbers. Advances in computing power and mathematical techniques have made 1024-bit RSA factoring feasible with sufficient resources. NIST recommends a minimum of 2048-bit RSA for current use, with 3072 or 4096-bit for systems requiring long-term security. CompTIA expects you to know that 1024-bit RSA is no longer secure.' },
  { id: 'D3-021', domainId: 3, front: 'ECC advantage over RSA — key insight', back: 'ECC provides equivalent security to RSA with dramatically smaller keys: a 256-bit ECC key is roughly equivalent to a 3072-bit RSA key in security strength. Smaller keys mean faster computation, lower memory usage, and reduced power consumption — critical advantages for mobile devices and IoT. ECC is used in ECDH (key exchange) and ECDSA (digital signatures).' },
  { id: 'D3-022', domainId: 3, front: 'Diffie-Hellman key exchange — what problem it solves', back: 'Diffie-Hellman allows two parties to establish a shared secret over an insecure channel without transmitting the secret itself. Each party generates a key pair, exchanges public keys, and uses their own private key combined with the other\'s public key to compute the same shared secret. This solves the key distribution problem for symmetric encryption. DH itself does not provide authentication — it must be combined with authentication to prevent MITM.' },
  { id: 'D3-023', domainId: 3, front: 'DHE and ECDHE — ephemeral keys and forward secrecy', back: 'DHE (Diffie-Hellman Ephemeral) and ECDHE (Elliptic Curve DHE) generate a fresh key pair for each session rather than using long-term keys. This provides Perfect Forward Secrecy (PFS): if the server\'s long-term private key is later compromised, past session keys cannot be derived and past traffic remains secure. ECDHE is mandatory in TLS 1.3.' },
  { id: 'D3-024', domainId: 3, front: 'TLS 1.3 improvements over TLS 1.2', back: 'TLS 1.3 (2018) removed all weak cipher suites (RC4, DES, 3DES, MD5), mandated ECDHE for key exchange (enforcing PFS), reduced the handshake from 2 round trips to 1 (faster connection setup), and introduced 0-RTT resumption. It eliminated RSA key exchange entirely. TLS 1.0 and 1.1 are deprecated and should be disabled. CompTIA tests TLS 1.3 as the current recommended standard.' },
  { id: 'D3-025', domainId: 3, front: 'Certificate types: DV, OV, EV, wildcard, SAN', back: 'DV (Domain Validated) — only proves domain ownership, issued quickly, cheapest. OV (Organization Validated) — validates organization identity, provides more assurance. EV (Extended Validation) — most rigorous vetting, used to display company name in browser (green bar, now less common). Wildcard (*. domain) covers all subdomains of one level. SAN (Subject Alternative Name) certificates cover multiple specific domains in one cert — most modern certificates use SANs.' },
  { id: 'D3-026', domainId: 3, front: 'Certificate chain of trust — root CA, intermediate CA, leaf cert', back: 'A root CA is a self-signed certificate at the top of the trust hierarchy — its private key is kept offline for maximum security. Intermediate CAs are signed by the root CA and are used for day-to-day certificate issuance. Leaf (end-entity) certificates are issued by intermediates and presented by websites and servers. Browsers trust root CAs built into the OS/browser trust store; the chain must be complete for verification.' },
  { id: 'D3-027', domainId: 3, front: 'Steganography vs. encryption — key difference', back: 'Encryption transforms data into unreadable ciphertext — it hides the content but makes it obvious that something secret is being communicated. Steganography hides the secret message within an innocent carrier (image, audio, video) so that the existence of the message is concealed. Steganography is security through obscurity; encryption provides mathematical security. The exam may test whether steganography provides confidentiality (it provides concealment, not the same thing).' },
  { id: 'D3-028', domainId: 3, front: 'Quantum computing threat to current cryptography', back: 'Quantum computers using Shor\'s algorithm can theoretically break RSA and ECC by efficiently factoring large numbers and solving discrete logarithm problems. Grover\'s algorithm reduces the effective strength of symmetric keys by half (AES-256 drops to 128-bit equivalent security against a quantum attacker). RSA and ECC are considered quantum-vulnerable; AES-256 and SHA-256 are considered quantum-resistant with current analysis.' },
  { id: 'D3-029', domainId: 3, front: 'Post-quantum cryptography (PQC) — why it matters now', back: 'NIST finalized the first PQC standards in 2024: CRYSTALS-Kyber (ML-KEM) for key encapsulation and CRYSTALS-Dilithium (ML-DSA) for digital signatures. Organizations should begin planning migration to PQC because: adversaries may be harvesting encrypted traffic today to decrypt later when quantum computers mature ("harvest now, decrypt later"), long-lived secrets need protection now, and migration takes years.' },
  { id: 'D3-030', domainId: 3, front: 'RAID 0 — purpose and security implications', back: 'RAID 0 stripes data across multiple disks for improved read/write performance — but provides NO redundancy. If any single disk fails, all data is lost. RAID 0 is inappropriate for any data requiring availability or durability. It is sometimes used for temporary scratch space or performance-critical non-critical data. The exam expects you to know RAID 0 = performance only, no fault tolerance.' },
  { id: 'D3-031', domainId: 3, front: 'RAID 1 — mirroring', back: 'RAID 1 duplicates (mirrors) data identically across two or more disks. If one disk fails, the other provides an exact copy. Read performance can improve (reads from multiple disks simultaneously); write performance is similar to a single disk. RAID 1 requires 2x the storage capacity for the usable space. It is the simplest form of redundancy and provides excellent protection against a single disk failure.' },
  { id: 'D3-032', domainId: 3, front: 'RAID 5 vs. RAID 6 — parity and fault tolerance', back: 'RAID 5 stripes data with single distributed parity across 3+ disks and can survive one disk failure. RAID 6 uses double parity across 4+ disks and can survive two simultaneous disk failures. RAID 6 provides greater fault tolerance at the cost of additional storage overhead and slightly lower write performance. For critical data, RAID 6 is preferred.' },
  { id: 'D3-033', domainId: 3, front: 'RAID 10 — what it is and its advantage', back: 'RAID 10 (1+0) combines mirroring and striping: data is first mirrored (RAID 1) then striped across the mirror pairs (RAID 0). It requires a minimum of 4 disks and uses 50% of total capacity. RAID 10 provides both high performance (striping) and high redundancy (mirroring) and can survive multiple disk failures as long as both disks in a mirror pair don\'t fail simultaneously.' },
  { id: 'D3-034', domainId: 3, front: 'RTO vs. RPO — which drives which decisions', back: 'RTO (Recovery Time Objective) defines the maximum acceptable downtime — how quickly systems must be back online. RPO (Recovery Point Objective) defines the maximum acceptable data loss — how old the restored data can be. RTO drives investments in standby systems, hot/warm/cold site selection, and failover automation. RPO drives backup frequency, replication synchronicity, and journaling. A lower RPO or RTO always costs more.' },
  { id: 'D3-035', domainId: 3, front: 'Full backup vs. incremental vs. differential backup', back: 'Full backup: copies all data every time — slowest to create, fastest to restore. Incremental: backs up only data changed since the last backup of any type — fastest to create, slowest to restore (need full + every incremental). Differential: backs up all data changed since the last full backup — moderate creation time, faster restore than incremental (need full + latest differential). CompTIA frequently asks which type is fastest to restore.' },
  { id: 'D3-036', domainId: 3, front: 'Geographic redundancy and geo-dispersal', back: 'Distributing systems and data across geographically separated locations to protect against site-level failures (natural disaster, power grid outage, regional network failure). Geo-dispersal ensures that a single event cannot destroy all copies of critical data or take down all systems simultaneously. Data sovereignty laws may restrict which countries data can be stored in, complicating geo-dispersal for global organizations.' },
  { id: 'D3-037', domainId: 3, front: 'Power redundancy: UPS, generator, dual power supply', back: 'UPS (Uninterruptible Power Supply) provides instantaneous battery backup when main power fails — bridging the gap until a generator starts. Generators provide sustained power during extended outages. Dual power supplies in servers allow one supply to fail without interrupting operation. Power redundancy follows the N+1 model: at least one more power source than the minimum needed to run.' },
  { id: 'D3-038', domainId: 3, front: 'Mantraps (security vestibules) — purpose and function', back: 'A mantrap is an entry control system using two interlocking doors: the outer door must close and lock before the inner door can open, allowing only one person through at a time. Mantraps prevent tailgating and enforce that each person must individually authenticate (badge, biometric) before entering a secure area. They are used in data centers, server rooms, and high-security facilities.' },
  { id: 'D3-039', domainId: 3, front: 'Bollards — physical security purpose', back: 'Short, sturdy vertical posts placed to prevent vehicle intrusion into pedestrian areas or secured facilities. Bollards protect against vehicle ramming attacks, which are used as physical attack vectors against buildings, crowds, or infrastructure. They are a preventive physical security control. Retractable bollards allow authorized vehicles while blocking unauthorized ones.' },
  { id: 'D3-040', domainId: 3, front: 'Biometric access controls — FAR and FRR', back: 'Biometric systems measure error rates: FAR (False Acceptance Rate) — incorrectly accepting an unauthorized user; FRR (False Rejection Rate) — incorrectly rejecting an authorized user. A lower FAR is more secure but increases FRR. The Crossover Error Rate (CER/EER) is where FAR = FRR — a lower CER indicates a more accurate biometric system. CompTIA expects you to know these metrics.' },
  { id: 'D3-041', domainId: 3, front: 'Faraday cage — what it blocks and why', back: 'A Faraday cage is an enclosure made of conductive material that blocks electromagnetic fields. It prevents radio frequency (RF) signals from entering or leaving, protecting against eavesdropping via electromagnetic emanation (TEMPEST attacks), preventing RF jamming, and blocking wireless signals. Faraday cages are used for forensic evidence storage, secure facilities, and testing isolated systems.' },
  { id: 'D3-042', domainId: 3, front: 'Air gap — use cases beyond IT', back: 'Air gaps are used in industrial control systems (SCADA/ICS) to isolate critical infrastructure from corporate networks, in nuclear facilities and power plants, for classified government systems, and for ballot systems in elections. Even air-gapped systems have been attacked via removable media (Stuxnet used infected USB drives to cross an air gap). Air gaps are a last resort, not a complete solution.' },
  { id: 'D3-043', domainId: 3, front: 'Network Access Control (NAC) — 802.1X and posture checking', back: 'NAC enforces policy compliance before network access is granted. 802.1X provides the authentication framework (supplicant → authenticator → RADIUS server). Posture checking evaluates device compliance: is the OS patched? Is AV running? Does the device have a valid certificate? Non-compliant devices are placed in a quarantine VLAN with remediation access only. NAC combines authentication with health assessment.' },
  { id: 'D3-044', domainId: 3, front: 'Load balancer security benefits beyond availability', back: 'Beyond distributing load and ensuring availability, load balancers provide: SSL/TLS termination (offloading decryption from backend servers), rate limiting and connection throttling, WAF integration, IP allowlisting/blocklisting, health checks to route traffic away from compromised servers, and a single point for enforcing HTTPS redirection. They also hide internal server details (IP addresses, server headers) from external clients.' },
  { id: 'D3-045', domainId: 3, front: 'CASB deployment modes — API-based vs. proxy-based', back: 'API-based CASBs connect directly to cloud services via their APIs and inspect content, enforce policies, and detect threats retroactively — good for SaaS applications. Proxy-based CASBs sit inline between users and cloud services, inspecting traffic in real time — better for forward proxy (controlling outbound cloud access) or reverse proxy (protecting cloud apps). API mode has no latency impact; proxy mode catches threats in real time.' },
  { id: 'D3-046', domainId: 3, front: 'HSM vs. TPM — key differences', back: 'An HSM (Hardware Security Module) is an external, network-attached or PCIe device that stores and manages cryptographic keys for servers and applications — used in CAs, payment systems, and key management infrastructure. A TPM (Trusted Platform Module) is a chip soldered onto a motherboard that provides key storage and platform integrity attestation for that specific computer. HSM is for enterprise key management; TPM is for individual device security.' },
  { id: 'D3-047', domainId: 3, front: 'Diffie-Hellman groups — what matters for the exam', back: 'DH groups define the strength of the DH key exchange. Higher group numbers indicate stronger security: Group 1 (768-bit) and Group 2 (1024-bit) are deprecated. Group 14 (2048-bit) is the minimum acceptable. Group 19 (256-bit ECC) and Group 21 (521-bit ECC) are strong modern choices. ECDHE groups are preferred over classic DH in TLS 1.3. CompTIA may test that low DH group numbers are insecure.' },
  { id: 'D3-048', domainId: 3, front: 'Symmetric key distribution challenge and how asymmetric solves it', back: 'Symmetric encryption is fast but requires both parties to have the same secret key — securely distributing that key is the key distribution problem. Asymmetric cryptography solves this: each party shares their public key openly; the other party uses it to encrypt a symmetric session key, which only the private key holder can decrypt. In practice, TLS uses asymmetric key exchange (ECDHE) to establish a symmetric session key, then uses symmetric encryption for data.' },
  { id: 'D3-049', domainId: 3, front: 'Community cloud vs. hybrid cloud — exam distinction', back: 'Community cloud is shared by multiple organizations with common requirements (same regulatory compliance, industry, or mission). Hybrid cloud combines private and public cloud environments connected for data/application portability. These are different deployment models. CompTIA tests all four: public, private, community, and hybrid. The exam often presents a scenario and asks which deployment model best fits the requirements.' },
  { id: 'D3-050', domainId: 3, front: 'Cryptographic hash function properties', back: 'A secure hash function must be: pre-image resistant (cannot reverse the hash to find the input), second pre-image resistant (cannot find a different input that produces the same hash as a known input), and collision resistant (cannot find any two inputs that produce the same hash). MD5 and SHA-1 have had collision attacks demonstrated and are no longer cryptographically secure for signatures.' },
  { id: 'D3-051', domainId: 3, front: 'PKI — certificate pinning', back: 'Certificate pinning is the practice of hard-coding the expected certificate or public key into an application so that it only accepts that specific certificate, even if a CA-signed certificate is presented. Pinning prevents MITM attacks that use fraudulent but CA-signed certificates (e.g., compromised CA, government-issued certs). Downside: pinned apps break when certificates are legitimately renewed.' },
  { id: 'D3-052', domainId: 3, front: 'Data in use — why it is the hardest state to protect', back: 'Data in use is being actively processed in memory — it must be decrypted to be used, making traditional encryption ineffective. Technologies addressing this: Trusted Execution Environments (TEE/Intel SGX/AMD SEV) create encrypted enclaves in memory; homomorphic encryption allows computation on encrypted data without decryption; confidential computing is an umbrella term for these approaches. Data in use protection is an emerging area on the SY0-701 exam.' },
  { id: 'D3-053', domainId: 3, front: 'SCADA and ICS network architecture security', back: 'SCADA (Supervisory Control and Data Acquisition) and ICS (Industrial Control Systems) networks should be air-gapped or connected to corporate networks only through a DMZ with data diodes or strict firewall rules. In ICS environments, availability is prioritized over confidentiality — patches may be delayed years because patching can disrupt production. Unidirectional gateways (data diodes) allow monitoring data out without allowing commands in.' },
  { id: 'D3-054', domainId: 3, front: 'Screened host architecture', back: 'A firewall configuration where a bastion host sits between an external router and the internal network. The external router filters gross traffic; the bastion host runs application proxies and provides detailed inspection. This differs from a DMZ (screened subnet) in that the bastion host sits directly in the network path rather than in a separate subnet. Less common today but may appear on the exam as a historical architecture.' },
  { id: 'D3-055', domainId: 3, front: 'What is a VLAN access port vs. a trunk port?', back: 'An access port is assigned to a single VLAN and carries traffic for only that VLAN — typically used for end devices (workstations, printers). A trunk port carries multiple VLANs simultaneously using 802.1Q tagging — typically used for switch-to-switch and switch-to-router links. Access ports are more secure for end devices; trunk ports require careful configuration to prevent VLAN hopping attacks.' },
  { id: 'D3-056', domainId: 3, front: 'Proxy server SSL inspection — how it works and the risk', back: 'A forward proxy performing SSL inspection acts as a MITM: it decrypts the client\'s HTTPS traffic, inspects it, re-encrypts, and forwards it. The proxy presents its own certificate (signed by an internal CA that clients are configured to trust). Security benefit: content filtering and DLP can inspect encrypted traffic. Risk: the proxy has visibility into all decrypted content; privacy and data handling must be carefully managed.' },
  { id: 'D3-057', domainId: 3, front: 'Certificate revocation — CRL vs. OCSP vs. OCSP Stapling', back: 'CRL (Certificate Revocation List): a periodically published list of revoked certificates — can be large and stale. OCSP: real-time per-certificate status check sent to the CA\'s OCSP responder — adds latency and privacy concerns (CA sees which cert you are checking). OCSP Stapling: the server proactively fetches and caches its own OCSP response and staples it to the TLS handshake — eliminates client round-trip to CA and improves privacy and performance.' },
  { id: 'D3-058', domainId: 3, front: 'IaC security scanning tools', back: 'Static analysis tools scan Infrastructure as Code templates before deployment to catch misconfigurations. Key tools: tfsec (Terraform), Checkov (multi-framework), Terrascan, and CloudFormation Guard. Common issues detected: unrestricted security group rules (0.0.0.0/0 on sensitive ports), unencrypted storage, publicly accessible buckets, overly permissive IAM roles, and disabled logging. Integrating these into CI/CD pipelines prevents misconfigs from reaching production.' },
  { id: 'D3-059', domainId: 3, front: 'High availability vs. fault tolerance — distinction', back: 'High availability (HA) minimizes downtime through redundancy and rapid failover — systems may briefly be unavailable during failover. Fault tolerance means a system continues operating without interruption even when components fail — zero downtime. HA is measured by uptime percentage (99.9%, 99.99%). Fault tolerance requires full redundancy at every layer and is significantly more expensive. RAID 1 + hot spare is fault tolerant; RAID 5 is HA.' },
  { id: 'D3-060', domainId: 3, front: 'Kubernetes security — pod security and network policies', back: 'Kubernetes orchestrates containers at scale. Key security controls: Pod Security Standards (restrict privileged containers, host path mounts, host networking), Network Policies (define which pods can communicate with which — implementing microsegmentation within the cluster), RBAC for the Kubernetes API (limit who can deploy, modify, or delete resources), and image scanning to prevent deploying vulnerable container images.' },
  { id: 'D3-061', domainId: 3, front: 'Wireless security — WPS vulnerability', back: 'WPS (Wi-Fi Protected Setup) was designed to simplify adding devices to a Wi-Fi network using an 8-digit PIN. A design flaw splits the PIN into two 4-digit halves checked independently, reducing the effective search space from 100 million to ~11,000 combinations. Brute-force tools can crack WPS PINs in hours. WPS should be disabled on all access points regardless of the network environment.' },
  { id: 'D3-062', domainId: 3, front: 'Passive vs. active reconnaissance in architecture assessment', back: 'Passive reconnaissance gathers information without directly interacting with the target — WHOIS lookups, DNS enumeration, Shodan searches, LinkedIn, job postings. It is undetectable. Active reconnaissance involves directly probing the target — port scanning, vulnerability scanning, ping sweeps — and may trigger IDS alerts. Architecture assessments consider both to understand the attacker\'s perspective before designing defenses.' },
  { id: 'D3-063', domainId: 3, front: 'Defense-in-depth applied to cloud architecture', back: 'In cloud environments, defense-in-depth means layering controls at every level: perimeter (NGFW, WAF), network (security groups, VPC flow logs, NACLs), identity (MFA, IAM least privilege), data (encryption at rest and in transit), and monitoring (CSPM, SIEM). The shared responsibility model means some layers are managed by the cloud provider and some by the customer — knowing which is which is critical.' },
  { id: 'D3-064', domainId: 3, front: 'Cryptographic agility — why organizations need it', back: 'Cryptographic agility is the ability to swap out cryptographic algorithms without redesigning entire systems. It is critical because algorithms become deprecated or broken: MD5 was broken, SHA-1 is deprecated, RSA 1024-bit is insecure, and RSA and ECC will be vulnerable to quantum computers. Systems designed with agility in mind (using abstraction layers for crypto primitives) can migrate to new algorithms far faster than hard-coded systems.' },
  { id: 'D3-065', domainId: 3, front: 'What goes in a DMZ? (exam context)', back: 'The DMZ hosts services that must be accessible from the internet but should not have direct access to the internal network. Common DMZ residents: web servers, email servers (SMTP gateway), DNS resolvers, VPN concentrators, reverse proxies, and bastion hosts. Internal database servers, file servers, and domain controllers should NEVER be in the DMZ. If a DMZ server is compromised, the internal network should still be protected by an inner firewall.' },

  // ─── Domain 4 Expansion: Security Operations (D4-001 through D4-070) ─────────

  { id: 'D4-001', domainId: 4, front: 'Vulnerability scan vs. penetration test — the key difference', back: 'A vulnerability scan is automated, non-exploiting, and identifies known vulnerabilities by comparing system configurations and versions against a vulnerability database. A penetration test is human-driven and actively attempts to exploit found vulnerabilities to determine actual impact. Vulnerability scans tell you what might be exploitable; pen tests confirm what is exploitable and show the real-world consequences.' },
  { id: 'D4-002', domainId: 4, front: 'CVE — Common Vulnerabilities and Exposures', back: 'CVE is a publicly maintained dictionary of known security vulnerabilities, each assigned a unique identifier (e.g., CVE-2021-44228 for Log4Shell). CVEs are curated by MITRE and enriched with CVSS scores by the National Vulnerability Database (NVD). CVE IDs provide a common reference language so security tools, vendors, and practitioners can discuss the same vulnerability without ambiguity.' },
  { id: 'D4-003', domainId: 4, front: 'CVSS base score factors — what does the 0-10 score measure?', back: 'CVSS v3.1 base score evaluates: Attack Vector (network/adjacent/local/physical), Attack Complexity (low/high), Privileges Required (none/low/high), User Interaction (none/required), Scope (changed/unchanged), Confidentiality Impact, Integrity Impact, and Availability Impact. Scores 0-3.9 = Low, 4-6.9 = Medium, 7-8.9 = High, 9-10 = Critical. A score of 10 means remotely exploitable with no privileges required and maximum impact.' },
  { id: 'D4-004', domainId: 4, front: 'False positive vs. false negative in vulnerability scanning', back: 'A false positive is when the scanner reports a vulnerability that does not actually exist — wastes remediation effort. A false negative is when a real vulnerability is not reported — far more dangerous because it creates false confidence. False negatives occur when signatures are outdated, when vulnerabilities are in obscure software, or when the scan is non-credentialed. Credentialed scans significantly reduce false negatives.' },
  { id: 'D4-005', domainId: 4, front: 'Credentialed vs. non-credentialed vulnerability scan', back: 'A credentialed scan uses valid authentication credentials to log into systems and inspect them from the inside — checking installed software versions, patch levels, registry settings, and configuration files. Results are far more accurate with fewer false negatives. A non-credentialed scan probes systems from the outside, seeing only what is exposed over the network — faster but misses many host-level vulnerabilities. The exam expects you to know credentialed = more thorough.' },
  { id: 'D4-006', domainId: 4, front: 'Patch management lifecycle steps', back: 'The patch lifecycle: (1) Inventory — know what software and versions are running; (2) Identify — monitor vendor advisories, CVE feeds, and CVSS scores; (3) Evaluate — assess severity and relevance; (4) Test — apply to a non-production environment first; (5) Deploy — push to production within SLA timelines based on severity; (6) Verify — confirm patching was successful; (7) Document — record what was patched and when.' },
  { id: 'D4-007', domainId: 4, front: 'Zero-day vulnerability — definition and response', back: 'A zero-day is a vulnerability unknown to the vendor or for which no patch exists. "Zero days" refers to the fact that defenders have had zero days to prepare. Response when no patch exists: implement compensating controls (WAF rules, IPS signatures, disabling the vulnerable feature), monitor intensely for exploitation attempts, apply virtual patching via WAF or IPS, and apply the vendor patch immediately upon release.' },
  { id: 'D4-008', domainId: 4, front: 'Responsible disclosure vs. full disclosure', back: 'Responsible (coordinated) disclosure: a researcher privately reports a vulnerability to the vendor, giving them 90 days (industry standard, established by Google Project Zero) to develop and release a patch before public disclosure. Full disclosure: immediately publishing all vulnerability details publicly — maximizes community awareness but gives attackers a head start. Bug bounty programs incentivize responsible disclosure.' },
  { id: 'D4-009', domainId: 4, front: 'Bug bounty programs — key characteristics', back: 'Bug bounty programs invite external security researchers to find and report vulnerabilities in exchange for monetary rewards or recognition. They extend testing coverage beyond what internal teams can achieve. Key elements: clearly defined scope (in-scope and out-of-scope systems), safe harbor provisions (legal protection for good-faith research), payout tiers based on severity, and a disclosure policy. Well-known programs include HackerOne and Bugcrowd platforms.' },
  { id: 'D4-010', domainId: 4, front: 'PICERL — the six incident response phases', back: 'Preparation — build IR capability before incidents occur. Identification — detect and confirm the incident, determine scope. Containment — stop the spread; short-term (isolate) then long-term (patch/harden while maintaining operations). Eradication — remove root cause: malware, backdoors, unauthorized accounts. Recovery — restore systems to production, monitor for recurrence. Lessons Learned — post-incident review, update plans and controls. Some frameworks abbreviate to PDCERR or PCERL.' },
  { id: 'D4-011', domainId: 4, front: 'Containment strategies: isolate, segment, quarantine', back: 'Isolation removes a system from all network connectivity — used for severely compromised systems. Segmentation moves a system into a restricted VLAN where it can communicate only with remediation tools. Quarantine is typically automated by NAC or EDR, placing a non-compliant or suspected device into a restricted network segment pending investigation. The choice depends on the criticality of the system and severity of the compromise.' },
  { id: 'D4-012', domainId: 4, front: 'Eradication vs. recovery — difference', back: 'Eradication removes the threat from the environment: deleting malware, closing backdoors, removing unauthorized accounts, patching the exploited vulnerability, and rebuilding compromised systems from known-good images. Recovery restores normal operations: bringing cleaned/rebuilt systems back online, restoring data from backups, and resuming business processes. Eradication must be verified complete before recovery begins, or re-infection is likely.' },
  { id: 'D4-013', domainId: 4, front: 'Runbook vs. playbook — definitions', back: 'A runbook is a set of step-by-step technical procedures for performing routine operational tasks (e.g., "how to restart the authentication service"). A playbook is a higher-level, strategic guide for responding to specific incident types (e.g., "ransomware response playbook") that includes decision points, escalation criteria, communication templates, and references to relevant runbooks. Playbooks guide the overall response; runbooks provide the technical steps.' },
  { id: 'D4-014', domainId: 4, front: 'SOAR — Security Orchestration, Automation, and Response', back: 'SOAR platforms automate repetitive IR tasks and orchestrate actions across security tools. When a SIEM fires an alert, a SOAR playbook can automatically enrich the alert (check threat intelligence, query the asset database), take initial action (quarantine an endpoint, block an IP), create a ticket, and notify the analyst — all in seconds. SOAR reduces MTTD and MTTR and decreases analyst alert fatigue from high-volume alerts.' },
  { id: 'D4-015', domainId: 4, front: 'Tabletop exercise — what it is and its value', back: 'A tabletop exercise (TTX) is a discussion-based simulation where key stakeholders walk through a hypothetical scenario (e.g., ransomware attack, data breach, DDoS) to evaluate response plans without actually deploying resources. It tests coordination, decision-making, communication, and process gaps. Tabletops are low-cost, high-value and should involve IT, security, legal, HR, PR, and executive leadership. Output: updated plans and identified gaps.' },
  { id: 'D4-016', domainId: 4, front: 'Purple team — what makes it different from red/blue', back: 'A purple team combines red team (offensive) and blue team (defensive) working together simultaneously and transparently, rather than separately with results revealed later. The red team attacks while the blue team tries to detect and respond in real time, immediately sharing what worked and what was missed. Purple teaming accelerates defensive improvement by providing immediate feedback loops that separate red/blue exercises lack.' },
  { id: 'D4-017', domainId: 4, front: 'MTTD vs. MTTR — metrics explained', back: 'Mean Time to Detect (MTTD): the average time from when an attack begins to when the security team detects it. Shorter MTTD reduces attacker dwell time. Mean Time to Respond (MTTR): the average time from detection to containment and remediation. Shorter MTTR limits damage. Both are key SOC performance KPIs. Industry studies show average dwell time (undetected attacker presence) ranges from weeks to months.' },
  { id: 'D4-018', domainId: 4, front: 'Chain of custody — why it matters in digital forensics', back: 'Chain of custody is the documented, unbroken record of every person who handled evidence, when they received it, and what actions they took. It is essential for legal proceedings: a broken chain of custody can make evidence inadmissible in court. For digital forensics, this means documenting every step from acquisition (who collected it, using what tools) through analysis and storage. All evidence transfers require signatures.' },
  { id: 'D4-019', domainId: 4, front: 'Order of volatility — correct sequence', back: 'Evidence should be collected from most volatile (disappears soonest) to least: (1) CPU registers and cache, (2) RAM — running processes, network connections, encryption keys, (3) Swap/pagefile, (4) Network state (ARP cache, routing tables, open connections), (5) Running processes and temporary files, (6) Hard disk storage, (7) Remote logging systems, (8) Archival media. RAM is the most commonly tested — power loss destroys all RAM contents.' },
  { id: 'D4-020', domainId: 4, front: 'Live acquisition vs. dead acquisition in forensics', back: 'Live acquisition captures data from a running system — essential for volatile data (RAM, running processes, network connections, encryption keys). The system remains powered on; tools like Volatility or WinPMem capture memory. Dead acquisition (offline) involves powering off the system and making a bit-for-bit forensic image of storage media using a write blocker. The trade-off: live acquisition risks contamination; dead acquisition preserves disk but loses volatile data.' },
  { id: 'D4-021', domainId: 4, front: 'Write blocker — what it is and why it is essential', back: 'A write blocker is a hardware or software device that prevents any write operations to a storage device while allowing read operations during forensic acquisition. Without a write blocker, simply connecting a storage device to an investigation computer can modify timestamps and file metadata, contaminating evidence. Hardware write blockers are preferred in legal proceedings because they are impossible to bypass through software error.' },
  { id: 'D4-022', domainId: 4, front: 'Forensic image — definition and verification', back: 'A forensic image is a bit-for-bit, sector-by-sector copy of a storage device that captures all data including deleted files, file system metadata, and unallocated space. The image is created using tools like FTK Imager or dd with a write blocker in place. Immediately after acquisition, a cryptographic hash (MD5 or SHA-256) is computed of both the original and the image — matching hashes prove the image is an exact, unaltered copy.' },
  { id: 'D4-023', domainId: 4, front: 'Legal hold — definition and implications', back: 'A legal hold (litigation hold) is a directive to preserve potentially relevant electronic evidence when litigation is anticipated or in progress. It suspends normal data retention policies and prevents deletion of relevant data. Failure to preserve data subject to legal hold is spoliation — a serious legal offense that can result in sanctions or adverse inference instructions to juries. IT and legal must coordinate legal hold implementation immediately.' },
  { id: 'D4-024', domainId: 4, front: 'Steganography detection in forensics', back: 'Detecting steganography requires specialized tools (steganalysis) that look for statistical anomalies in image, audio, or video files — differences from normal file structures that suggest embedded content. Tools include StegDetect, Stegsolve, and binwalk. Forensic investigators check for unexpectedly large file sizes, unusual file structures, and statistical irregularities in least-significant bits of images.' },
  { id: 'D4-025', domainId: 4, front: 'MFA types: TOTP, HOTP, push, hardware token', back: 'TOTP (Time-based OTP): generates codes that change every 30 seconds using the current time and a shared secret — used in Google Authenticator. HOTP (HMAC-based OTP): codes based on a counter that increments with each use — no time sync required. Push notification: app sends an approval request to the user\'s phone — convenient but vulnerable to push bombing (MFA fatigue). Hardware token (FIDO2/YubiKey): phishing-resistant, cryptographic authentication — strongest option.' },
  { id: 'D4-026', domainId: 4, front: 'MFA fatigue / push bombing attack', back: 'An attacker who has stolen a user\'s credentials bombards the user\'s MFA app with push notification approval requests, hoping the user will approve one out of frustration or confusion. This bypasses MFA without any technical vulnerability. Mitigations: require number matching in push notifications (user must match a number shown on the login screen), use FIDO2 hardware keys instead of push MFA, and train users to never approve unexpected MFA requests.' },
  { id: 'D4-027', domainId: 4, front: 'SSO — benefits and security risks', back: 'SSO benefits: users authenticate once and access many applications, reducing password fatigue and improving productivity. Centralized access control simplifies provisioning and deprovisioning. Security risks: SSO infrastructure becomes a single high-value target — compromising the SSO identity provider grants access to all connected applications. SSO must be protected with MFA and strict monitoring. Lack of SSO deprovisioning is also risky when employees leave.' },
  { id: 'D4-028', domainId: 4, front: 'SAML — what it is and how it enables federated SSO', back: 'SAML (Security Assertion Markup Language) is an XML-based standard for passing authentication and authorization assertions between an Identity Provider (IdP) and a Service Provider (SP). The user authenticates at the IdP, which creates a signed XML assertion. The SP trusts this assertion and grants access without requiring re-authentication. SAML enables SSO across organizational boundaries (federated identity). Common IdPs: Okta, Azure AD, ADFS.' },
  { id: 'D4-029', domainId: 4, front: 'OAuth 2.0 — authorization not authentication', back: 'OAuth 2.0 is an authorization framework that allows users to grant third-party applications access to their resources (at a resource server) without sharing credentials — the application receives an access token, not the user\'s password. OAuth 2.0 handles WHAT you can access. It does not inherently verify WHO you are (authentication). OpenID Connect (OIDC) is built on OAuth 2.0 and adds the authentication layer.' },
  { id: 'D4-030', domainId: 4, front: 'OIDC (OpenID Connect) — what it adds to OAuth', back: 'OpenID Connect (OIDC) is an identity layer built on top of OAuth 2.0 that adds authentication. While OAuth 2.0 provides an access token for resource authorization, OIDC additionally provides an ID token (a signed JWT) that contains claims about the authenticated user (name, email, sub). OIDC enables single sign-on in modern web and mobile applications. The exam question: OAuth = authorization; OIDC = authentication + authorization.' },
  { id: 'D4-031', domainId: 4, front: 'RBAC vs. ABAC — when to use each', back: 'RBAC assigns permissions to roles (e.g., "Manager" role can approve expenses), and users are assigned roles — simple to manage, best for organizations with clear, stable job functions. ABAC makes access decisions based on dynamic attributes of the user, resource, and environment (e.g., "allow access if user.department=Finance AND document.classification=Internal AND time.hour<18") — more flexible and granular but more complex. Large enterprises often use ABAC for fine-grained control.' },
  { id: 'D4-032', domainId: 4, front: 'MAC — Mandatory Access Control in practice', back: 'MAC is enforced by the operating system based on security labels — users cannot override these policies, even for resources they own. Classification labels (Unclassified, Confidential, Secret, Top Secret) are assigned to both subjects and objects; subjects can only access objects at or below their clearance level. MAC is used in government and military systems. SELinux and AppArmor implement MAC on Linux systems.' },
  { id: 'D4-033', domainId: 4, front: 'DAC — Discretionary Access Control and its weakness', back: 'In DAC, the owner of a resource decides who can access it — they grant and revoke permissions at their discretion. Unix permissions (owner/group/other with read/write/execute bits) are a classic DAC example. The weakness: DAC is prone to privilege creep (users accumulate permissions over time), Trojan horse attacks (malware running as a user inherits all their permissions), and inconsistent policy enforcement across the organization.' },
  { id: 'D4-034', domainId: 4, front: 'PAM — Privileged Access Management and its key features', back: 'PAM manages, controls, and audits privileged accounts (root, admin, service accounts). Key features: password vaulting (storing privileged credentials in an encrypted vault and rotating them automatically), just-in-time access (granting privileges only when needed), session recording (full video-like recording of privileged sessions for audit), and command filtering (restricting which commands a privileged user can run). PAM is a critical control for insider threat and lateral movement.' },
  { id: 'D4-035', domainId: 4, front: 'Just-in-Time (JIT) access — definition and benefit', back: 'JIT access provisions elevated privileges only for the duration of a specific, approved task and automatically revokes them when the task is complete or the time window expires. This eliminates standing privileges — persistent elevated access that attackers can steal and abuse indefinitely. JIT is a key PAM feature that enforces least privilege over time, not just at provisioning. Every privilege use is logged and tied to an approved request.' },
  { id: 'D4-036', domainId: 4, front: 'LDAP and Active Directory — security context', back: 'LDAP (Lightweight Directory Access Protocol) is the protocol for querying and modifying directory services like Active Directory (AD). AD is Microsoft\'s implementation of a directory service for Windows domains, storing user accounts, computer accounts, and group policies. LDAP injection is a web vulnerability where unsanitized input modifies LDAP queries. AD is a high-value target because it controls authentication for the entire domain.' },
  { id: 'D4-037', domainId: 4, front: 'RADIUS vs. TACACS+ — key differences', back: 'RADIUS: IETF standard, encrypts only the password field in authentication packets, combines authentication and authorization in one response, primarily used for network access (Wi-Fi, VPN, 802.1X). TACACS+: Cisco-proprietary, encrypts the entire packet body, separates authentication, authorization, and accounting (AAA) into distinct operations, supports granular per-command authorization — primarily used for device administration (router/switch CLI access). The exam: RADIUS = network access; TACACS+ = device management.' },
  { id: 'D4-038', domainId: 4, front: 'EDR — Endpoint Detection and Response capabilities', back: 'EDR solutions continuously monitor and record endpoint activity, using behavioral analytics and threat intelligence to detect malicious behavior that signature-based AV misses. Key capabilities: process creation monitoring, file system and registry activity recording, network connection logging, memory analysis, lateral movement detection, and automated response (quarantine, process kill). EDR also provides telemetry for threat hunting and forensic investigation after an incident.' },
  { id: 'D4-039', domainId: 4, front: 'DLP — Data Loss Prevention types and deployment', back: 'DLP prevents unauthorized exfiltration or exposure of sensitive data. Deployment types: Network DLP (inline inspection of email and web traffic — blocks credit card numbers in outbound emails), Endpoint DLP (agent on workstations — blocks copying sensitive files to USB or uploading to cloud storage), Cloud DLP (integrated with CASB — monitors data in SaaS applications). DLP requires accurate data classification to function — you cannot protect data you cannot identify.' },
  { id: 'D4-040', domainId: 4, front: 'HIPS vs. HIDS — host-based security distinction', back: 'HIDS (Host-based Intrusion Detection System) monitors system activity, log files, and file integrity on a host and generates alerts but takes no automated action — it detects and notifies. HIPS (Host-based Intrusion Prevention System) goes further: it can automatically block suspicious activity, terminate processes, and prevent file changes in real time. HIPS trades some risk of false positives blocking legitimate activity for the benefit of automated prevention.' },
  { id: 'D4-041', domainId: 4, front: 'Next-generation antivirus vs. traditional antivirus', back: 'Traditional AV uses signature databases to identify known malware — updated signatures are required to detect new threats and it cannot detect zero-days or polymorphic malware. NGAV (Next-Generation AV) uses behavioral analysis, machine learning, and cloud-based threat intelligence to detect malicious behavior patterns regardless of signature. NGAV detects fileless attacks, living-off-the-land techniques, and zero-day exploits that traditional AV misses.' },
  { id: 'D4-042', domainId: 4, front: 'Application whitelisting vs. blacklisting', back: 'Blacklisting blocks known bad applications — simpler to implement but ineffective against new malware. Whitelisting (allow-listing) permits only explicitly approved applications to run and blocks everything else — far more secure but requires significant effort to build and maintain the approved application list. CompTIA SY0-701 terminology uses "allow-listing" rather than "whitelisting." Allow-listing is one of the most effective controls against malware.' },
  { id: 'D4-043', domainId: 4, front: 'IDS vs. IPS — inline vs. passive, detect vs. prevent', back: 'IDS is passive: it monitors a copy of traffic (via SPAN port or network tap) and generates alerts — it does not block traffic. If an IDS fails, traffic flows normally. IPS is inline: all traffic passes through it, and it can drop malicious packets in real time — if an IPS fails, traffic may be blocked (fail-close) or allowed (fail-open depending on configuration). IPS must be tuned carefully because false positives block legitimate traffic.' },
  { id: 'D4-044', domainId: 4, front: 'NIDS vs. HIDS — placement and visibility', back: 'NIDS (Network IDS) is deployed at network chokepoints (perimeter, between segments) to monitor traffic flowing through the network — it sees broad traffic patterns. It cannot inspect encrypted traffic without decryption capability. HIDS is installed on individual endpoints and sees everything happening on that host: process activity, file changes, log entries, and local network connections. Both are complementary: NIDS provides breadth; HIDS provides depth.' },
  { id: 'D4-045', domainId: 4, front: 'SIEM — what it collects, correlates, and alerts on', back: 'SIEM aggregates log data from firewalls, IDS/IPS, endpoints, servers, applications, and identity systems. It normalizes logs into a common format, applies correlation rules (e.g., "5 failed logins from the same IP within 10 minutes"), generates alerts, stores logs for compliance, and provides dashboards for security operations. The correlation engine is SIEM\'s core value — detecting attack patterns that individual device logs would not reveal.' },
  { id: 'D4-046', domainId: 4, front: 'NetFlow — what it captures and its security use', back: 'NetFlow captures flow records: source/destination IP, source/destination port, protocol, bytes transferred, packets, and duration — but NOT payload content. It is metadata, not a full packet capture. Security uses: detecting data exfiltration (unusual large outbound flows), C2 communication patterns (periodic small outbound connections), lateral movement (internal hosts scanning other internal hosts), and DDoS (volumetric inbound traffic spikes).' },
  { id: 'D4-047', domainId: 4, front: 'PCAP — packet capture and its forensic value', back: 'PCAP (Packet Capture) captures the full content of network packets including headers and payloads. Tools: Wireshark (GUI analysis), tcpdump (command-line capture). PCAP is the gold standard for network forensics — analysts can reconstruct TCP sessions, extract files transferred over the network, analyze malware C2 communication, and identify data exfiltration. Limitation: significant storage requirements and privacy concerns from capturing all network content.' },
  { id: 'D4-048', domainId: 4, front: 'DNS filtering and DNS sinkholing', back: 'DNS filtering blocks resolution of known malicious domains, preventing users from reaching phishing sites, malware distribution points, and C2 servers by intercepting the DNS query. DNS sinkholing redirects queries for malicious domains to a controlled "sinkhole" IP — this not only blocks the connection but also identifies infected hosts within the network that are attempting to contact known-malicious domains. Both are detective and preventive controls.' },
  { id: 'D4-049', domainId: 4, front: 'Honeypot vs. honeynet — purpose and intelligence value', back: 'A honeypot is a single decoy system configured to appear valuable to attackers and to detect, record, and analyze their activities. A honeynet is a network of honeypots connected to simulate a realistic network environment. Both generate high-confidence alerts (legitimate users have no reason to interact with decoys) and provide threat intelligence on attacker tools and techniques. Low-interaction honeypots have limited services; high-interaction honeypots run real OS/applications.' },
  { id: 'D4-050', domainId: 4, front: 'Network tap vs. SPAN port — packet capture methods', back: 'A network tap (Test Access Point) is a physical hardware device inserted into a network link that passively copies all traffic — it sees everything, cannot be detected, and does not affect traffic flow. A SPAN (Switched Port Analyzer) port is a switch configuration that mirrors traffic from specified ports to a monitoring port — software-based, free, but can drop packets under high load. For high-fidelity forensic capture, taps are preferred.' },
  { id: 'D4-051', domainId: 4, front: 'Threat hunting — proactive vs. reactive security', back: 'Threat hunting is a proactive, analyst-led process of searching through security data looking for hidden threats that have evaded automated detection. Hunters form a hypothesis (e.g., "an attacker is using PowerShell for lateral movement based on threat intelligence about a current APT group"), then search SIEM/EDR data to confirm or deny it. Reactive security waits for alerts; threat hunting assumes compromise has already occurred and looks for evidence.' },
  { id: 'D4-052', domainId: 4, front: 'HOTP vs. TOTP — counter-based vs. time-based OTP', back: 'HOTP (HMAC-based OTP) generates a code using a shared secret and a counter that increments with each use — no time synchronization required between client and server, but codes can be replayed if an unused code is captured. TOTP (Time-based OTP) generates codes using the shared secret and the current time (30-second windows) — requires time synchronization but codes expire automatically, preventing replay. TOTP is more common in modern authenticator apps.' },
  { id: 'D4-053', domainId: 4, front: 'Directory services — LDAP protocol details for the exam', back: 'LDAP (Lightweight Directory Access Protocol) uses a hierarchical structure: DC (Domain Component) at the top, OU (Organizational Unit) for grouping, CN (Common Name) for individual entries. Default ports: 389 (LDAP plaintext), 636 (LDAPS — LDAP over TLS). LDAP bind operations authenticate users. LDAP injection occurs when user input is embedded in LDAP queries without sanitization, potentially bypassing authentication or exposing directory data.' },
  { id: 'D4-054', domainId: 4, front: 'Principle of least privilege — beyond access control', back: 'Least privilege applies beyond user accounts to: processes (services should run with minimum required OS permissions), applications (apps should request only necessary permissions), networks (firewall rules should allow only necessary traffic), and code (functions should have access only to the data they need). Excess privilege anywhere in the stack is an attack opportunity. Regular privilege reviews catch accumulated excess permissions (privilege creep).' },
  { id: 'D4-055', domainId: 4, front: 'Incident response communication — legal and PR considerations', back: 'IR communications must consider: legal counsel review of all external communications (attorney-client privilege may apply to IR reports), PR coordination for breach notifications, regulatory notification requirements (GDPR 72-hour deadline, state breach laws), law enforcement coordination (FBI for major incidents), and internal stakeholder briefings. IR plans should pre-define the communication tree and templates to avoid delays when time matters most.' },
  { id: 'D4-056', domainId: 4, front: 'Evidence preservation during containment', back: 'Containment must balance speed (stop the spread) with evidence preservation (do not destroy forensic data). Before isolating a system, capture: running process list, network connections, RAM if feasible. Avoid: rebooting (clears RAM, modifies timestamps), running antivirus scans (modifies files), and deleting logs (destroys evidence). Forensic acquisition of disk and memory should happen as soon as possible after containment.' },
  { id: 'D4-057', domainId: 4, front: 'Credentialed vulnerability scan — what it checks', back: 'With valid credentials, a scanner can: verify installed software versions against vulnerability databases (identifying local vulnerabilities), check patch levels, inspect registry settings and configuration files, enumerate installed services and their permissions, review local user accounts and group memberships, and identify outdated or vulnerable software not exposed over the network. Credentialed scans are required by PCI-DSS and other compliance frameworks for accurate internal assessments.' },
  { id: 'D4-058', domainId: 4, front: 'Vulnerability management SLA — severity-based patch timelines', back: 'Organizations should define patch SLAs based on CVSS severity: Critical (9.0-10.0) — patch within 24-72 hours; High (7.0-8.9) — patch within 7-30 days; Medium (4.0-6.9) — patch within 30-90 days; Low (0-3.9) — patch at next maintenance window. CISA\'s Known Exploited Vulnerabilities (KEV) catalog overrides CVSS-based prioritization — vulnerabilities being actively exploited in the wild require immediate attention regardless of base CVSS score.' },
  { id: 'D4-059', domainId: 4, front: 'Log sources in a SIEM — what to collect', back: 'Critical log sources: firewall and IDS/IPS logs, authentication events (Active Directory login success/failure), DNS query logs, DHCP logs (tie IP to hostname), endpoint security (EDR/AV) logs, web server and application logs, cloud platform audit logs (CloudTrail, Azure Monitor), and network flow data. Correlation across multiple log sources is what enables SIEM to detect attacks that would be invisible in any single log source.' },
  { id: 'D4-060', domainId: 4, front: 'Forensic tools — common tools for the exam', back: 'Disk imaging: FTK Imager, Autopsy, dd. Memory analysis: Volatility, Rekall. Network forensics: Wireshark, NetworkMiner. Log analysis: Splunk, Elastic. Mobile forensics: Cellebrite, Oxygen Forensics. Password recovery: Hashcat (offline), John the Ripper. Malware analysis: REMnux, Cuckoo Sandbox. CompTIA does not expect deep tool proficiency but expects candidates to recognize what each category of tool does.' },
  { id: 'D4-061', domainId: 4, front: 'Physical security: two-person integrity vs. dual control', back: 'Two-person integrity requires two authorized individuals to be present for sensitive operations — neither can act alone. Dual control is similar but specifically means that each person holds part of the information needed and neither can complete the action alone (e.g., each has half a combination). Both controls prevent insider abuse of privileged access. They are implemented for activities like accessing encryption keys, initiating wire transfers, and launching weapons.' },
  { id: 'D4-062', domainId: 4, front: 'Security camera systems — IP camera security considerations', back: 'IP-based security cameras are IoT devices with their own attack surface. Common issues: default credentials (manufacturers often ship cameras with admin/admin), unencrypted video streams, outdated firmware with known vulnerabilities, and unnecessary services (Telnet, FTP). Mitigations: change default credentials immediately, place cameras on an isolated VLAN, disable unused services, encrypt the video stream, and monitor for firmware updates.' },
  { id: 'D4-063', domainId: 4, front: 'User and Entity Behavior Analytics (UEBA) — how it detects threats', back: 'UEBA establishes behavioral baselines for individual users and entities over time (what systems they access, when, from where, what volumes of data). It then uses statistical models and ML to flag deviations: an employee accessing systems they never use, downloading 10x their normal data volume, logging in at 3 AM, or accessing data from a foreign country. UEBA is effective against insider threats and compromised credentials that have no malware signature.' },
  { id: 'D4-064', domainId: 4, front: 'Canary tokens — lightweight deception', back: 'A canary token is a unique, trackable artifact (a fake document, URL, AWS credential, email address, or database entry) embedded in a system. If the canary is accessed, the security team receives an immediate alert. Canary tokens require no maintenance and provide high-confidence alerts because legitimate users have no reason to access them. They detect attackers who have already breached the perimeter and are exploring the environment.' },
  { id: 'D4-065', domainId: 4, front: 'Data retention and log retention for compliance', back: 'Different regulations require different log retention periods: PCI-DSS requires 12 months of audit log retention (3 months immediately available). HIPAA requires 6 years of security documentation. SOX requires 7 years for financial records. GDPR requires logs be retained only as long as necessary and personal data in logs must be handled appropriately. IR investigations often discover that insufficient log retention made it impossible to determine when or how an attack started.' },
  { id: 'D4-066', domainId: 4, front: 'Threat intelligence types: tactical, operational, strategic', back: 'Tactical intelligence: low-level IoCs (IPs, domains, file hashes) — directly actionable in security tools. Operational intelligence: attacker TTPs, campaign information, tools used — informs detection rule development and IR playbooks. Strategic intelligence: high-level trends, geopolitical context, threat actor motivations — informs executive risk decisions and long-term security strategy. A mature security program consumes all three levels.' },
  { id: 'D4-067', domainId: 4, front: 'De-identification and pseudonymization in forensics and data handling', back: 'De-identification removes all identifying information from data so that individuals cannot be identified. Pseudonymization replaces identifying fields with artificial identifiers (pseudonyms) — the original data can be recovered with a separate key. Both reduce privacy risk during data analysis and log management. GDPR distinguishes between the two: pseudonymized data is still personal data; truly de-identified data is not.' },
  { id: 'D4-068', domainId: 4, front: 'Automated malware analysis — sandbox behavior', back: 'Automated sandboxes execute suspicious files in isolated environments and record their behavior: files created/modified/deleted, registry changes, network connections made, processes spawned, APIs called, and screen activity. This behavioral analysis detects malware that evades signature detection. Sophisticated malware may detect sandboxes (check for mouse movement, specific hardware, short uptime) and alter behavior. Multiple sandbox environments with different configurations improve detection.' },
  { id: 'D4-069', domainId: 4, front: 'Incident metrics — what to track and report', back: 'Key IR metrics: number of incidents per period (by severity), MTTD, MTTR, containment time, incidents by initial access vector (phishing, vulnerability, credential theft), recurrence rate (same incident type recurring suggests insufficient remediation), cost per incident, and percentage of incidents detected internally vs. by external parties. Metrics demonstrate program value, identify trends, and justify security investments to leadership.' },
  { id: 'D4-070', domainId: 4, front: 'eDiscovery and its relationship to forensics', back: 'eDiscovery (electronic discovery) is the process of identifying, collecting, and producing electronically stored information (ESI) in response to legal proceedings. Forensic techniques ensure ESI is collected in a legally defensible manner (chain of custody, hash verification). Legal hold notifications must be sent to custodians before ESI collection begins. Proper eDiscovery processes require coordination between legal, IT, HR, and security teams.' },

  // ─── Domain 5 Expansion: Security Program Management (D5-001 through D5-065) ─

  { id: 'D5-001', domainId: 5, front: 'Risk formula — conceptual model', back: 'Risk is often expressed as: Risk = Threat × Vulnerability × Impact. All three factors must exist for risk to be present: a threat without a vulnerability cannot exploit anything; a vulnerability without a threat poses no danger; a threat exploiting a vulnerability with no impact is acceptable. This model is used to prioritize risk treatments — reduce any of the three factors to reduce overall risk.' },
  { id: 'D5-002', domainId: 5, front: 'Risk register — what it contains', back: 'A risk register is the central document of a risk management program. Contents: unique risk ID, risk description, risk category, affected assets, likelihood rating, impact rating, risk score (likelihood × impact), current controls, risk owner (individual responsible), treatment plan and timeline, residual risk after controls, and date last reviewed. Risk registers are living documents reviewed and updated regularly by risk owners and security leadership.' },
  { id: 'D5-003', domainId: 5, front: 'Inherent risk vs. residual risk', back: 'Inherent risk is the level of risk before any controls are applied — the raw risk. Residual risk is what remains after controls are implemented. The goal of security controls is to reduce inherent risk to a residual risk level that falls within the organization\'s risk tolerance. No control eliminates risk entirely; management must formally accept residual risk. The difference between inherent and residual risk demonstrates control effectiveness.' },
  { id: 'D5-004', domainId: 5, front: 'Risk appetite vs. risk tolerance — the distinction', back: 'Risk appetite is a broad, qualitative statement of how much risk an organization is willing to accept in pursuit of its mission ("we have a low appetite for customer data breach risk"). Risk tolerance is more specific and often quantitative — the acceptable variation around a risk objective ("we will tolerate no more than $1M in annual incident-related losses"). Both are set by the board and executive leadership and communicated as policy.' },
  { id: 'D5-005', domainId: 5, front: 'Risk transference — cyber insurance details', back: 'Risk transference shifts the financial consequences of a risk to a third party. Cyber insurance is the primary mechanism. Coverage typically includes: breach response costs, legal and regulatory fees, forensic investigation, notification costs, credit monitoring for affected individuals, ransomware payments, business interruption losses, and third-party liability. Insurers require documented security controls (MFA, EDR, backups) before underwriting and during policy renewal.' },
  { id: 'D5-006', domainId: 5, front: 'Quantitative risk: SLE, ARO, ALE formulas with examples', back: 'SLE (Single Loss Expectancy) = Asset Value × Exposure Factor. Example: Server worth $200,000, EF = 50% → SLE = $100,000. ALE (Annual Loss Expectancy) = SLE × ARO. Example: SLE = $100,000, ARO = 0.5 (once every 2 years) → ALE = $50,000. A security control costing $30,000/year that reduces ALE to $10,000 is worth implementing (saves $40,000/year). CompTIA frequently tests these formulas — know them precisely.' },
  { id: 'D5-007', domainId: 5, front: 'Qualitative risk — likelihood × impact matrix', back: 'Qualitative risk assessment plots risks on a matrix with likelihood on one axis and impact on the other, using categories like Low/Medium/High or a 5×5 scale. High likelihood + high impact = critical risk requiring immediate treatment. Low likelihood + low impact = acceptable risk. This approach is faster and more accessible to non-technical stakeholders than quantitative analysis but lacks the precision needed for financial cost-benefit decisions.' },
  { id: 'D5-008', domainId: 5, front: 'BIA — Business Impact Analysis outputs', back: 'BIA outputs include: list of critical business functions ranked by importance, MTD (Maximum Tolerable Downtime) for each function, RTO and RPO requirements derived from MTD, identification of internal and external dependencies for each function, financial impact of disruption per hour/day, and recommended recovery priority order. BIA is the foundation of BCP/DRP planning — without it, recovery plans may restore the wrong systems first.' },
  { id: 'D5-009', domainId: 5, front: 'BCP vs. DRP — scope and focus', back: 'BCP (Business Continuity Plan) focuses on maintaining critical business operations during any disruption — it covers people, processes, alternate facilities, communications, and supply chain, not just technology. DRP (Disaster Recovery Plan) is the IT-focused subset of BCP concerned with restoring technology systems and data. Example: BCP defines how finance staff work from an alternate location; DRP defines how the ERP system is restored to that location. BCP is broader; DRP is a component of BCP.' },
  { id: 'D5-010', domainId: 5, front: 'MTTR vs. MTBF — reliability metrics for risk planning', back: 'MTTR (Mean Time to Repair): the average time required to repair a failed component and restore it to operation — measures repairability. MTBF (Mean Time Between Failures): the average time a component operates between failures — measures reliability. Lower MTTR and higher MTBF are both desirable. These metrics drive redundancy decisions: a component with low MTBF and high MTTR is a high-risk single point of failure that needs redundancy.' },
  { id: 'D5-011', domainId: 5, front: 'Single point of failure — definition and mitigation', back: 'A single point of failure (SPOF) is any component whose failure would cause an entire system or process to stop functioning. SPOFs in IT include: a single internet link, one firewall without a failover, a single DNS server, a non-redundant power supply. SPOFs are identified during BIA and mitigated through redundancy (duplicate components), clustering (active-active), or failover (active-passive). The goal is eliminating SPOFs from all critical systems.' },
  { id: 'D5-012', domainId: 5, front: 'NIST CSF 2.0 — the six functions', back: 'NIST CSF 2.0 (released 2024) added a sixth function to the original five: Govern (establishing governance structures and risk management policies — the new addition), Identify (understanding assets and risks), Protect (implementing safeguards), Detect (monitoring and detecting events), Respond (taking action on detected incidents), Recover (restoring affected capabilities). Govern sits at the center, contextualizing all other functions.' },
  { id: 'D5-013', domainId: 5, front: 'NIST SP 800-53 — control catalog purpose', back: 'NIST SP 800-53 is the security and privacy control catalog for federal information systems, containing hundreds of controls organized into 20 control families (AC - Access Control, AU - Audit, SC - System and Communications, etc.). Organizations select controls based on system categorization (Low/Moderate/High impact under FIPS 199). SP 800-53 is required for FISMA compliance and FedRAMP authorization and is widely adopted in private sector as a best practice framework.' },
  { id: 'D5-014', domainId: 5, front: 'ISO 27001 — what makes it an international standard', back: 'ISO/IEC 27001 is an international standard specifying requirements for an ISMS (Information Security Management System). Unlike NIST frameworks (primarily US-focused), ISO 27001 is recognized globally. Organizations can pursue formal third-party certification after a successful audit. Annex A contains 93 security controls across four themes. ISO 27001 certification demonstrates to customers and partners that the organization manages information security systematically.' },
  { id: 'D5-015', domainId: 5, front: 'SOC 2 Type I vs. Type II — difference', back: 'SOC 2 Type I report: evaluates whether controls are suitably designed at a specific point in time — a snapshot assessment. SOC 2 Type II report: evaluates whether controls were designed appropriately AND operated effectively over a period (typically 6-12 months) — demonstrates sustained security practice. Type II is more valuable to customers because it shows controls actually work over time, not just that they exist on paper. SaaS vendors frequently obtain SOC 2 Type II to satisfy enterprise customer security requirements.' },
  { id: 'D5-016', domainId: 5, front: 'PCI-DSS — who must comply and key requirements', back: 'Any organization that stores, processes, or transmits payment card data must comply with PCI-DSS. The 12 requirements cover: install/maintain firewalls, protect cardholder data, encrypt transmission, use antivirus, develop/maintain secure systems, restrict access by need-to-know, assign unique IDs to users, restrict physical access, monitor/test networks, maintain information security policies. Compliance is validated by QSA (Qualified Security Assessor) or SAQ (Self-Assessment Questionnaire) based on transaction volume.' },
  { id: 'D5-017', domainId: 5, front: 'HIPAA — protected data and covered entities', back: 'HIPAA protects PHI (Protected Health Information) — any individually identifiable health information including medical records, billing, diagnoses, prescriptions, and insurance information. Covered entities: healthcare providers, health plans, and healthcare clearinghouses that transmit health information electronically. Business associates (vendors processing PHI on behalf of covered entities) also must comply. The Security Rule requires administrative, physical, and technical safeguards.' },
  { id: 'D5-018', domainId: 5, front: 'GDPR — key requirements for the exam', back: 'GDPR applies to any organization processing personal data of EU residents. Key requirements: lawful basis for processing (consent, legitimate interest, contract, etc.), data subject rights (access, rectification, erasure/right to be forgotten, portability, objection), data protection by design and default, mandatory breach notification to supervisory authority within 72 hours and to affected individuals "without undue delay," DPO required for certain organizations, and restrictions on transferring data outside the EU.' },
  { id: 'D5-019', domainId: 5, front: 'GDPR — right to be forgotten (erasure)', back: 'Article 17 of GDPR gives individuals the right to request deletion of their personal data when: the data is no longer necessary for the original purpose, consent is withdrawn, the data was processed unlawfully, or erasure is required by law. Organizations must erase the data from all systems including backups and logs unless legal obligations require retention. This creates challenges for data stored in immutable or distributed systems.' },
  { id: 'D5-020', domainId: 5, front: 'FISMA — US federal security requirements', back: 'FISMA requires all federal agencies to: categorize information systems by impact level (using FIPS 199), implement appropriate NIST SP 800-53 controls, conduct annual security reviews, obtain Authority to Operate (ATO) before deploying systems, continuously monitor controls, and report to OMB. FISMA also applies to contractors operating federal information systems. FedRAMP is the FISMA-equivalent framework for cloud services used by federal agencies.' },
  { id: 'D5-021', domainId: 5, front: 'FedRAMP — cloud services for US government', back: 'FedRAMP (Federal Risk and Authorization Management Program) provides a standardized approach for authorizing cloud products used by federal agencies. Cloud Service Providers (CSPs) seek FedRAMP authorization by implementing NIST SP 800-53 controls and undergoing assessment by a Third-Party Assessment Organization (3PAO). Once authorized, the "authorize once, use everywhere" model allows any federal agency to use the authorization. FedRAMP authorization is often required in RFPs for government cloud contracts.' },
  { id: 'D5-022', domainId: 5, front: 'Data classification levels — government and commercial', back: 'Government: Unclassified, Controlled Unclassified Information (CUI), Confidential, Secret, Top Secret. Commercial: Public (anyone can see), Internal (employees only), Confidential (limited internal distribution), Restricted/Highly Confidential (executive, legal, regulatory). Data classification drives handling requirements: labeling, encryption requirements, access control, transmission methods, and destruction procedures. Misclassification creates either under-protection (risk) or over-protection (cost).' },
  { id: 'D5-023', domainId: 5, front: 'Data owner vs. data custodian vs. data processor vs. data subject', back: 'Data owner: the business manager responsible for defining classification and acceptable use of data. Data custodian: IT/operations personnel responsible for implementing the owner\'s directives — backup, encryption, access controls. Data processor: an entity that processes data on behalf of the data controller (GDPR term) — a cloud provider or SaaS vendor. Data subject: the individual whose personal data is collected (GDPR term). Knowing these roles and their responsibilities is tested on the exam.' },
  { id: 'D5-024', domainId: 5, front: 'PII vs. PHI — definitions and regulatory context', back: 'PII (Personally Identifiable Information): any data that can identify a specific individual — name, address, SSN, email, IP address, biometrics. PII is protected by GDPR, CCPA, and state breach notification laws. PHI (Protected Health Information): any individually identifiable health information held by HIPAA-covered entities — medical records, diagnoses, prescriptions, billing codes. PHI is a subset of PII but subject to HIPAA\'s specific requirements. Both require encryption, access controls, and breach notification.' },
  { id: 'D5-025', domainId: 5, front: 'Data at rest vs. in transit vs. in use — controls', back: 'At rest (stored on disk/database): encrypt using AES-256, apply access controls, monitor access. In transit (moving over network): encrypt using TLS 1.2+, VPNs for private network traffic, avoid transmitting over untrusted networks unencrypted. In use (in memory/being processed): hardest to protect — use Trusted Execution Environments (TEE), minimize time data spends in use in plaintext, use memory protection (ASLR, DEP). The exam may ask which state lacks comprehensive encryption protection.' },
  { id: 'D5-026', domainId: 5, front: 'Data destruction methods — which to use when', back: 'Overwriting (wiping): writing patterns over all sectors — effective for functioning hard drives, not for SSDs (wear leveling leaves data in over-provisioned areas). Degaussing: strong magnetic field destroys magnetic media (HDDs, tapes) — does not work on SSDs. Crypto-erasure (cryptographic erasure): destroying the encryption key for encrypted data — instant, works for all media types but requires all data was encrypted. Physical destruction (shredding, crushing, incineration): most secure, required for highly sensitive data. SSDs require either crypto-erasure or physical destruction.' },
  { id: 'D5-027', domainId: 5, front: 'Data retention policy — what it defines', back: 'A data retention policy specifies: how long each category of data must be kept (retention period), where it must be stored during retention, who is responsible for managing it, when and how it must be securely destroyed, and how to handle legal holds that supersede normal retention schedules. Retention periods are driven by legal requirements (SOX 7 years, HIPAA 6 years, PCI-DSS 1 year for logs) and business needs. Over-retention increases breach exposure and e-discovery costs.' },
  { id: 'D5-028', domainId: 5, front: 'Data sovereignty — implications for global organizations', back: 'Data sovereignty means data is subject to the laws of the country where it is stored or processed. A company storing EU customer data in the US must comply with both GDPR (EU) and potentially US law, including government surveillance laws. This creates tension: GDPR restricts data transfers to countries without adequate protection laws; US law may compel disclosure. Organizations use data residency commitments from cloud providers and Standard Contractual Clauses (SCCs) to navigate this.' },
  { id: 'D5-029', domainId: 5, front: 'Third-party risk assessment — process and outputs', back: 'Third-party risk assessment evaluates vendors with access to organizational data or systems. Process: identify vendors by data access level (critical, significant, minimal), send security questionnaires, review SOC 2 reports or audit results, perform on-site or virtual assessments for critical vendors, evaluate findings against risk tolerance, and establish contractual security requirements. Outputs: vendor risk rating, required remediation, contractual security obligations, and monitoring frequency.' },
  { id: 'D5-030', domainId: 5, front: 'Supply chain attack — SolarWinds example', back: 'In 2020, attackers (later attributed to Russia\'s SVR) compromised SolarWinds\' build process and injected malware (SUNBURST) into the Orion software update. 18,000+ organizations automatically installed the trojanized update, giving attackers stealthy access to their networks. The SolarWinds attack illustrates why software supply chain integrity is critical: code signing alone was bypassed because the legitimate build process was compromised. SBOM (Software Bill of Materials) helps identify affected components.' },
  { id: 'D5-031', domainId: 5, front: 'MOU — Memorandum of Understanding', back: 'An MOU is a non-binding agreement documenting the mutual understanding between parties about shared objectives, responsibilities, and expectations. In cybersecurity, MOUs govern information sharing partnerships, system interconnections between organizations, and cooperative incident response arrangements. Because MOUs are non-binding, they do not carry the legal force of a contract. They are used to establish trust and set expectations before a formal contract (ISA, MSA) is negotiated.' },
  { id: 'D5-032', domainId: 5, front: 'MSA — Master Service Agreement', back: 'A Master Service Agreement is an umbrella contract that establishes the general terms and conditions governing the relationship between a customer and a service provider. Individual project or service-specific details are addressed in Statements of Work (SOWs) or SLAs that operate under the MSA. Security provisions in MSAs typically include: data handling requirements, breach notification obligations, audit rights, acceptable use policies, and liability allocation.' },
  { id: 'D5-033', domainId: 5, front: 'SLA — Service Level Agreement security provisions', back: 'SLAs define the minimum acceptable service levels a provider must deliver. Security-relevant SLA provisions: uptime/availability guarantees, incident response and notification timelines (e.g., "notify within 4 hours of discovering a breach"), patch deployment timelines, audit rights (right to inspect security controls), data location restrictions, and penalties for non-compliance (service credits, contract termination). SLAs without security provisions leave the customer without recourse for security failures.' },
  { id: 'D5-034', domainId: 5, front: 'NDA — Non-Disclosure Agreement in security context', back: 'An NDA is a legal contract binding one or both parties to keep specified information confidential. In security contexts: NDAs with vendors before sharing system architecture details, with pen testers before assessments, with new employees (covering trade secrets and customer data), and at employee termination. NDAs are an administrative (legal) security control — they create legal liability for disclosure but do not technically prevent it. They must be combined with technical controls like access restrictions.' },
  { id: 'D5-035', domainId: 5, front: 'BPA — Business Partnership Agreement', back: 'A BPA defines the terms of a business relationship between partners, including responsibilities, governance, intellectual property, and obligations. From a security perspective, BPAs should address: how shared data is classified and protected, what security standards the partner must meet, incident response coordination obligations, and who bears liability for security incidents. BPAs are often supplemented by an ISA (Interconnection Security Agreement) when systems are connected.' },
  { id: 'D5-036', domainId: 5, front: 'Right-to-audit clause — what it allows', back: 'A right-to-audit clause in a contract allows the customer to inspect the vendor\'s security controls, processes, and compliance status — either directly or through a third-party auditor. This is critical for high-risk vendors with access to sensitive data or systems. Without a right-to-audit clause, customers must rely entirely on vendor-provided attestations (SOC 2 reports) which may not cover all relevant areas. Audit rights should be included in all critical vendor contracts.' },
  { id: 'D5-037', domainId: 5, front: 'SBOM — Software Bill of Materials', back: 'An SBOM is a formal, structured list of all software components, libraries, and dependencies included in a software product — similar to a food ingredients list. SBOMs enable rapid identification of systems affected by a newly discovered vulnerability in a component (e.g., Log4Shell). CISA and the US government have mandated SBOMs for software sold to federal agencies. SBOMs improve supply chain visibility and reduce mean time to respond to component-level vulnerabilities.' },
  { id: 'D5-038', domainId: 5, front: 'Security awareness training types', back: 'Computer-Based Training (CBT): self-paced online modules on security topics — scalable, trackable. Phishing simulations: controlled fake phishing emails measuring click rates and providing immediate contextual training — the most effective anti-phishing control. Role-based training: specialized training for specific job functions (IT admins, finance, executives) covering risks relevant to their roles. Instructor-led training: workshops and classroom sessions for hands-on or complex topics. Annual security awareness training is required by HIPAA, PCI-DSS, and CMMC.' },
  { id: 'D5-039', domainId: 5, front: 'Security policy vs. standard vs. guideline vs. procedure', back: 'Policy: "why" and "what" — high-level, board-approved, mandatory, technology-agnostic ("All data must be encrypted at rest"). Standard: "how much" — specific, mandatory technical or process requirements ("Encryption must use AES-256"). Guideline: "suggested" — recommended but not mandatory, advisory ("Consider using a hardware security key for MFA"). Procedure: "step-by-step how" — detailed operational instructions ("Here is how to configure AES-256 encryption on an S3 bucket"). The hierarchy: Policy → Standard → Guideline → Procedure.' },
  { id: 'D5-040', domainId: 5, front: 'AUP — Acceptable Use Policy key elements', back: 'An AUP defines what employees may and may not do with organizational IT resources (computers, internet, email, systems). Key provisions: approved uses of internet and email, prohibited activities (illegal content, unauthorized software, sharing credentials, cryptocurrency mining on company systems), privacy notice (organization may monitor usage), data handling obligations, and consequences for violations. All employees should sign the AUP at hire and annually thereafter. It is both a security and legal document.' },
  { id: 'D5-041', domainId: 5, front: 'BYOD policy — security risks and controls', back: 'BYOD allows personal devices for work, creating risks: inability to enforce full security policies on personal devices, mixing personal and corporate data (accidental sharing), device loss or theft exposing corporate data, malware on personal device infecting corporate systems, and difficulty wiping corporate data without affecting personal data. Controls: MDM enrollment (with containerization to separate personal/corporate), network segmentation (personal devices on guest VLAN), conditional access policies requiring minimum device health.' },
  { id: 'D5-042', domainId: 5, front: 'Clean desk policy — why it matters', back: 'A clean desk policy requires employees to clear their desks of sensitive documents, removable media, and credentials when leaving their workspace. It prevents shoulder surfing, opportunistic information theft, and dumpster diving. Enforcement includes: locking cabinets for sensitive documents, shredding bins for document disposal, clear screen policy (lock screen when away), and periodic management walkthroughs. Simple to implement but often overlooked — directly mitigates physical security threats.' },
  { id: 'D5-043', domainId: 5, front: 'Security metrics and KPIs — examples the exam tests', back: 'Common security KPIs: Mean Time to Detect (MTTD), Mean Time to Respond (MTTR), patch compliance rate (% of systems patched within SLA), phishing click rate and report rate, number of critical vulnerabilities open past SLA, number of security incidents per quarter by severity, and false positive rate. Good KPIs are measurable, tied to business risk, reported regularly to leadership, and used to demonstrate security program maturity and justify budget.' },
  { id: 'D5-044', domainId: 5, front: 'Risk-based vs. compliance-based security program', back: 'A compliance-based program focuses on meeting regulatory checkboxes — pass the audit and move on. It may miss significant risks not covered by the compliance framework and create a false sense of security. A risk-based program identifies the most significant threats to the organization and prioritizes controls accordingly — compliance is a by-product. Risk-based programs are more effective but require mature risk management capabilities. CompTIA expects candidates to understand that compliance does not equal security.' },
  { id: 'D5-045', domainId: 5, front: 'Privacy Impact Assessment (PIA) — when it is conducted', back: 'A PIA (called DPIA — Data Protection Impact Assessment — under GDPR) is conducted before implementing new systems, processes, or technologies that involve collecting, using, or sharing personal data — particularly when processing is likely to result in high risk to individuals (large-scale profiling, processing of special categories, systematic monitoring). A DPIA is mandatory under GDPR for high-risk processing. PIAs identify privacy risks early when they are cheaper to mitigate.' },
  { id: 'D5-046', domainId: 5, front: 'Audit types: internal, external, third-party', back: 'Internal audit: performed by the organization\'s own audit function — provides ongoing assurance and identifies issues early; findings are confidential. External audit: performed by an independent firm — required for many compliance certifications (SOC 2, ISO 27001, PCI-DSS QSA); provides independent validation. Third-party audit: a customer or partner may conduct or commission an audit of a vendor — validates that the vendor meets contractual security requirements. Exam tip: external = independent, third-party = customer-driven.' },
  { id: 'D5-047', domainId: 5, front: 'Black box, white box, gray box penetration testing', back: 'Black box: tester has zero prior knowledge of the target — simulates an external attacker without any inside information. Most realistic but may miss issues a knowledgeable attacker would find. White box: tester has full knowledge — source code, network diagrams, credentials — simulates an insider or a well-prepared attacker. Most thorough. Gray box: partial knowledge provided — simulates a user with limited insider access or an attacker who has done reconnaissance. Most common real-world approach balancing realism and thoroughness.' },
  { id: 'D5-048', domainId: 5, front: 'Risk avoidance as a risk treatment', back: 'Risk avoidance means choosing not to engage in the activity that creates the risk. For example: deciding not to offer a certain product because the regulatory compliance cost is too high, not connecting a legacy system to the internet, or not processing certain categories of sensitive data. Risk avoidance completely eliminates the specific risk but may sacrifice business opportunity. It is appropriate when the risk exceeds the benefit of the activity.' },
  { id: 'D5-049', domainId: 5, front: 'Risk mitigation — control selection framework', back: 'Mitigation reduces the likelihood or impact of a risk by implementing controls. Control selection framework: identify threat and vulnerability, determine which controls address them (preventive, detective, corrective), estimate cost of control, compare cost to reduction in ALE, implement the most cost-effective controls. The goal is not to eliminate risk entirely but to reduce it to an acceptable residual level within budget constraints.' },
  { id: 'D5-050', domainId: 5, front: 'Risk acceptance — formal documentation requirements', back: 'Risk acceptance is a formal decision by management to acknowledge a risk and do nothing additional about it — either because the cost of mitigation exceeds the risk value or it falls within risk tolerance. Acceptance must be documented: who accepted the risk, when, why, under what conditions, and how long the acceptance is valid. Undocumented risk acceptance is not true acceptance — it is negligence. Risk registers track accepted risks for periodic review.' },
  { id: 'D5-051', domainId: 5, front: 'Security program governance — board and CISO relationship', back: 'Effective security governance requires: board-level oversight (security as a board agenda item, not just IT), a CISO with direct access to executive leadership and the board, clear security policies approved by leadership, a defined risk appetite communicated throughout the organization, and regular security reporting (risk posture, incidents, KPIs) to the board. Without board-level engagement, security programs struggle to obtain adequate resources and authority.' },
  { id: 'D5-052', domainId: 5, front: 'Penetration test reporting — what a good report contains', back: 'A professional pen test report contains: executive summary (business risk, overall posture — for non-technical stakeholders), technical findings (detailed vulnerability descriptions, evidence, exploitation steps, screenshots), risk ratings (Critical/High/Medium/Low — typically using CVSS or similar), remediation recommendations (specific, actionable guidance), and a remediation verification plan. Findings should be ranked by risk so organizations address the most critical issues first.' },
  { id: 'D5-053', domainId: 5, front: 'Information sharing and ISAC/ISAO', back: 'ISACs (Information Sharing and Analysis Centers) are industry-specific organizations that collect and share cybersecurity threat intelligence among members — e.g., FS-ISAC (financial), H-ISAC (healthcare), E-ISAC (energy). ISAOs (Information Sharing and Analysis Organizations) are more flexible, sector-agnostic sharing communities. Both operate under legal frameworks that allow competitive organizations to share threat data without antitrust concerns. Participation improves collective defense.' },
  { id: 'D5-054', domainId: 5, front: 'Security architecture review — when it occurs', back: 'Security architecture reviews should occur at major milestones: before deploying new systems (design review), before major infrastructure changes, when merging with or acquiring another company, annually for critical systems, after significant incidents that reveal architectural weaknesses, and when regulatory requirements change. Architecture reviews assess whether the design meets security requirements and identify gaps before systems are built or changed — far cheaper than remediating production systems.' },
  { id: 'D5-055', domainId: 5, front: 'Key risk indicators (KRIs) vs. key performance indicators (KPIs)', back: 'KRIs are leading indicators that signal increasing risk before an incident occurs: rising phishing simulation click rates, increasing numbers of unpatched critical vulnerabilities, declining security training completion rates. KPIs are lagging indicators measuring security program performance after the fact: MTTD, MTTR, number of incidents. Effective security programs track both — KRIs for early warning, KPIs for program effectiveness measurement. Both are reported to leadership.' },
  { id: 'D5-056', domainId: 5, front: 'Interconnection Security Agreement (ISA)', back: 'An ISA documents the security requirements for connecting two organizations\' networks. It specifies: what data flows between the networks and its classification, what security controls each party must implement at the connection point, encryption requirements for data in transit, monitoring and logging requirements, incident response coordination procedures, and authorization requirements for changes to the connection. ISAs are required by FISMA for federal system interconnections.' },
  { id: 'D5-057', domainId: 5, front: 'Data Loss Prevention — policy implementation steps', back: 'Implementing DLP: (1) Classify data and identify what must be protected (PII, PHI, PCI data, IP). (2) Discover where sensitive data resides (data discovery scanning). (3) Define DLP policies (what constitutes a violation — e.g., credit card number in an email). (4) Deploy DLP in monitor-only mode first to understand traffic and tune rules. (5) Move to enforcement mode after tuning to minimize false positives. (6) Review incidents and refine policies continuously.' },
  { id: 'D5-058', domainId: 5, front: 'Compliance vs. security — understanding the gap', back: 'Organizations that pass compliance audits may still be breached because: (1) Compliance frameworks assess controls at a point in time — attackers exploit dynamic weaknesses. (2) Compliance is minimum baseline — the minimum required to pass an audit may not be enough to defeat sophisticated attackers. (3) Compliance scope may exclude critical systems. (4) Checkbox compliance does not require understanding of actual threats. Risk-based security aims to defend against real threats, treating compliance as a floor not a ceiling.' },
  { id: 'D5-059', domainId: 5, front: 'Security program maturity models', back: 'Maturity models assess how well-developed a security program is. Examples: CMMC (1-3 levels), C2M2 (Cybersecurity Capability Maturity Model), NIST CSF maturity tiers (1-4). General progression: Level 1 (ad hoc/reactive — firefighting), Level 2 (documented, repeatable processes), Level 3 (defined, proactive policies), Level 4 (managed, measured and quantified), Level 5 (optimizing, continuously improving). Higher maturity correlates with lower breach probability and faster response.' },
  { id: 'D5-060', domainId: 5, front: 'Cybersecurity budget justification — risk-based approach', back: 'Effective security budget justification uses: ALE to quantify the financial risk being mitigated, comparison of control cost vs. ALE reduction (a $50K control that reduces ALE by $200K is clearly justified), benchmark data (industry peers\' security spend as % of IT budget), regulatory penalty avoidance (GDPR fines up to 4% of revenue), and incident cost data (average breach costs from IBM/Ponemon reports). Presenting security spending as risk reduction resonates with executives and boards.' },
  { id: 'D5-061', domainId: 5, front: 'Workforce security — background checks and access management', back: 'Personnel security controls include: pre-employment background checks (criminal history, identity verification, reference checks), ongoing monitoring for high-clearance roles (credit checks, foreign travel reporting), separation of duties to prevent fraud, mandatory vacation to detect anomalies, termination procedures (immediate access revocation, device return, exit interview), and non-disclosure agreements. Human risk is often the weakest link — personnel controls address the insider threat.' },
  { id: 'D5-062', domainId: 5, front: 'Vendor tiering and proportional risk management', back: 'Not all vendors deserve the same level of scrutiny. Vendors should be tiered by risk: Tier 1 (critical — access to sensitive data or core systems, e.g., cloud infrastructure, MSSP) — full assessment, SOC 2 review, contractual requirements, quarterly monitoring. Tier 2 (significant — limited access) — questionnaire, annual review. Tier 3 (minimal — no data access, e.g., office supplies) — standard contract terms only. Proportional approach focuses security resources on highest-risk relationships.' },
  { id: 'D5-063', domainId: 5, front: 'Regulatory landscape for SY0-701 — key laws and frameworks', back: 'Key regulations tested: GDPR (EU personal data), HIPAA (US healthcare data), PCI-DSS (payment card data), FISMA (US federal systems), GLBA (US financial institutions), SOX (US public company financial controls), COPPA (US children\'s online privacy). Frameworks (voluntary, not laws): NIST CSF, NIST SP 800-53, ISO 27001, CIS Controls, SOC 2 (attestation). Know which are legally binding (laws/regulations) vs. guidance (frameworks/standards).' },
  { id: 'D5-064', domainId: 5, front: 'Security control effectiveness measurement', back: 'Measuring control effectiveness: define the threat the control addresses and the expected reduction in risk, establish metrics (e.g., phishing simulation click rate measures awareness training effectiveness), baseline before implementation, measure after implementation, compare to target. Periodic control testing (penetration testing, red team exercises, compliance audits) validates that controls work as designed. Ineffective controls should be updated, replaced, or supplemented with compensating controls.' },
  { id: 'D5-065', domainId: 5, front: 'Information security program — continuous improvement cycle', back: 'A mature security program follows a continuous improvement cycle: Assess (identify gaps and risks), Plan (develop remediation roadmap and prioritize), Implement (deploy controls and train users), Monitor (measure effectiveness with KPIs and KRIs), Review (periodic audits, pen tests, and after-action reviews), and Improve (incorporate lessons learned and new threat intelligence). This aligns with the PDCA (Plan-Do-Check-Act) model and the continuous monitoring requirements of NIST RMF and ISO 27001.' },
];
